  ('e6c92a2b-a14d-4a02-8aaa-e542f0cb054f', 'mathematics', '1', 'Operations with Numbers', '1.1', 1, 'Combine and Separate Quantities', 'Give students opportunities to separate and combine quantities using a variety of concrete materials and explain their thinking. This builds foundational understanding of addition and subtraction concepts.', 'hands-on', '["Counters","Cubes","Buttons","Beads","Local materials (shells, seeds, bottle caps)"]'::jsonb, NULL, NULL, 20, 'individual', 1, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('68512bb8-3382-4709-89d9-331fd5d25e8e', 'mathematics', '1', 'Operations with Numbers', '1.1', 2, 'Multiple Representation Story Problems', 'Present story problem structures for multiple representations. Example: "There are 5 pieces of fruit in a bowl. If there are two kinds of fruit, what might they be and how many of each?" Students explore different ways to partition 5.', 'hands-on', '["Fruit manipulatives","Counters","Drawing paper"]'::jsonb, NULL, NULL, 25, 'individual', 2, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('499be448-f5c3-4bbf-9d8c-927617efb5ef', 'mathematics', '1', 'Operations with Numbers', '1.1', 3, 'Missing Value Problems', 'Solve missing value problems using manipulatives. Example: "If there are 12 counters in a bag, some red and some blue, and 8 are red, how many are blue?" Students use concrete materials to find the unknown.', 'hands-on', '["Two-color counters","Paper bags","Number cards"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('a7c4c981-e250-41d8-a601-d30af0c27de8', 'mathematics', '1', 'Operations with Numbers', '1.1', 4, 'Number Line Walking Game', 'Use games to demonstrate how addition and subtraction relate to each other. Students physically walk on a large floor number line, moving forward for addition and backward for subtraction.', 'game', '["Floor number line (tape or mat)","Number cards","Dice"]'::jsonb, NULL, NULL, 25, 'individual', 4, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('5be745f0-0c85-4c3a-a5d9-63a041084223', 'mathematics', '1', 'Operations with Numbers', '1.1', 5, 'Outdoor Collection and Comparison', 'Collect materials outside and compare, combine, and separate quantities. Use leaves, shells, popsicle sticks, and bottle caps. Connect to data collection activities.', 'hands-on', '["Collection bags","Sorting trays","Local natural materials"]'::jsonb, NULL, NULL, 30, 'individual', 5, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('a843e4e5-1036-4340-b6c7-a4bce08a218e', 'mathematics', '1', 'Operations with Numbers', '1.1', 6, 'Taking Away Action Songs', 'Sing action songs that focus on taking away or removing. Songs like "Ten Little Monkeys" and "Ten Green Bottles" help students understand subtraction through music and movement.', 'movement', '["Song lyrics chart","Finger puppets (optional)"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('87650941-3ae5-473d-b934-692ab6bc3875', 'mathematics', '1', 'Operations with Numbers', '1.1', 7, 'Pan Scale Comparison', 'Use a pan scale to show different amounts and discuss which is larger, smaller, and what is the difference. Students physically see the concept of comparing quantities.', 'hands-on', '["Pan balance scale","Counting cubes","Small objects of equal weight"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('f550b3eb-b6c1-418e-9a5b-b68dd3d2fb71', 'mathematics', '1', 'Operations with Numbers', '1.1', 8, 'Tower Building Comparison', 'Make towers with blocks to discuss which is taller, shorter, and find the difference. Count the blocks to quantify the comparison.', 'hands-on', '["Connecting cubes","Building blocks"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('622d3449-ead0-4941-870f-1ebd9e279870', 'mathematics', '1', 'Operations with Numbers', '1.1', 9, 'Height Comparison Activity', 'Compare heights of students or objects (link to measurement). Use non-standard units to find the difference between heights.', 'hands-on', '["Measuring tape","Connecting cubes","String"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('1497832e-87df-49c7-848c-09912da50e54', 'mathematics', '1', 'Operations with Numbers', '1.1', 10, 'Story Problem Acting', 'Play with sets of objects to act out combining, separating, and comparing. Model different story problems to find the missing value through dramatic play.', 'hands-on', '["Various manipulatives","Story problem cards"]'::jsonb, NULL, NULL, 25, 'individual', 10, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('879de5ec-b3e5-4d70-a7fe-83b3a5329724', 'mathematics', '1', 'Operations with Numbers', '1.1', 11, 'Inverse Relationship Demonstration', 'Show how addition and subtraction undo each other. Example: 6 + 3 = 9 and 9 – 3 = 6. Use manipulatives to demonstrate that 3 + 2 = 5 then 5 – 3 = 2.', 'hands-on', '["Counters","Number cards","Whiteboard"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('ec98d184-0325-42c0-834c-3a0c96b4eeda', 'mathematics', '1', 'Operations with Numbers', '1.1', 12, 'Fact Family Exploration', 'Look at a group of numbers and say how they are related. Example fact family: 4 + 3 = 7, 3 + 4 = 7, 7 – 3 = 4, 7 – 4 = 3. Complete fact families vertically and horizontally from given diagrams.', 'hands-on', '["Fact family cards","Number triangles","Worksheets"]'::jsonb, NULL, NULL, 25, 'individual', 12, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('677d6556-1504-4800-bad2-635a3d15bef2', 'mathematics', '1', 'Operations with Numbers', '1.1', 13, 'Diagram to Equation', 'Introduce using a diagram or picture to communicate an addition equation. Record what the diagram shows by writing the number sentence.', 'hands-on', '["Drawing paper","Counters","Crayons"]'::jsonb, NULL, NULL, 20, 'individual', 13, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('5d6c1327-deaa-4f17-a45d-bab544f17b16', 'mathematics', '1', 'Operations with Numbers', '1.1', 14, 'Counter Diagram Recording', 'Use diagrams with counters: "How many blue counters? How many red counters? 5 and 3 make how many counters?" Record equation 5 + 3 = 8.', 'hands-on', '["Two-color counters","Recording sheets","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 14, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('0cb0f835-1561-4887-ac57-a6e16ff77c98', 'mathematics', '1', 'Operations with Numbers', '1.1', 15, 'Counting On Vocabulary Building', 'Build vocabulary: "a way to add is by counting on from a given number" (6 + 2 = 8). Practice counting on strategy with manipulatives.', 'hands-on', '["Number line","Counters","Vocabulary cards"]'::jsonb, NULL, NULL, 15, 'individual', 15, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('dd9fdaf1-d6f4-48c9-8e70-e955b5b43b22', 'mathematics', '1', 'Operations with Numbers', '1.1', 16, 'Counting Back Vocabulary Building', 'Build vocabulary: "a way to subtract is by counting backward from the greater number" (5 – 2 = 3). Practice counting back strategy.', 'hands-on', '["Number line","Counters","Vocabulary cards"]'::jsonb, NULL, NULL, 15, 'individual', 16, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('b8b9883f-eaa2-48b3-b425-d2e294a49b39', 'mathematics', '1', 'Operations with Numbers', '1.1', 17, 'Fact Family Brainstorm', 'Brainstorm that a fact family includes all addition and subtraction facts using the same numbers. Create fact family houses or triangles.', 'hands-on', '["Fact family templates","Number cards","Markers"]'::jsonb, NULL, NULL, 20, 'individual', 17, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('a203b03b-9fe9-4ce7-959f-293b73de861b', 'mathematics', '1', 'Operations with Numbers', '1.1', 18, 'Tens Frame Subitizing', 'Place counters in a tens frame (any amount up to ten) - supports subitising. Students quickly recognize quantities without counting.', 'hands-on', '["Tens frames","Counters","Flash cards"]'::jsonb, NULL, NULL, 15, 'individual', 18, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('479f8e61-8486-4e4b-a275-78c51143c6a5', 'mathematics', '1', 'Operations with Numbers', '1.1', 19, 'Tens Frame Counting On', 'Place red counters in tens frame, ask how many, then add different coloured counters. Use two different colours to encourage counting on and support subitising.', 'hands-on', '["Tens frames","Two-color counters"]'::jsonb, NULL, NULL, 20, 'individual', 19, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('143b9d44-cec5-42f4-beb8-e2278b84c035', 'mathematics', '1', 'Operations with Numbers', '1.1', 20, 'Bus Simulation Activity', 'Use caution tape to model a bus with 16 spaces (wrapping around seats). Probe students: "How many passengers can the bus hold? How do you know?" Place students in the taped area and ask: "How many passengers on the bus? How many more needed to fill it?"', 'movement', '["Caution tape or rope","Chairs","Number cards"]'::jsonb, NULL, NULL, 30, 'individual', 20, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('135c9afa-f0ab-41c0-91c0-5a8b58dd4131', 'mathematics', '1', 'Operations with Numbers', '1.1', 21, 'Tens Frame Story Completion', 'Make copies of tens frames for students to complete addition equations for given stories. Explore number bonds to 10 - different number combinations that add up to 10.', 'hands-on', '["Tens frame worksheets","Counters","Story problem cards"]'::jsonb, NULL, NULL, 25, 'individual', 21, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('ae39922a-f5f7-4bd7-aef2-e362ee4a8386', 'mathematics', '1', 'Operations with Numbers', '1.1', 22, 'Number Line Story Representation', 'Allow students to place manipulatives on a number line to represent story problems. Use number line to represent addition problems up to 20 (concrete to abstract).', 'hands-on', '["Number lines","Small manipulatives","Story cards"]'::jsonb, NULL, NULL, 20, 'individual', 22, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('4758667c-24e7-4820-9309-264b0f4f0678', 'mathematics', '1', 'Operations with Numbers', '1.1', 23, 'Number Strip Counting On', 'Use counters on number strips. Example: 4 red counters, then add 3 different coloured counters. Students count on to find the total.', 'hands-on', '["Number strips","Two-color counters"]'::jsonb, NULL, NULL, 15, 'individual', 23, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('ee695825-4590-4845-9b4e-ec1825690d5b', 'mathematics', '1', 'Operations with Numbers', '1.1', 24, 'Number Grid Subtraction Game', 'Work in pairs using number grids to answer subtraction questions by counting back. Partners take turns creating and solving subtraction problems.', 'game', '["100 chart or number grid","Counters","Problem cards"]'::jsonb, NULL, NULL, 25, 'individual', 24, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('541e7bb2-6c0b-4801-8616-f78d6bfd1dfe', 'mathematics', '1', 'Operations with Numbers', '1.1', 25, 'Egg Carton Addition', 'Using an egg carton with a given amount, find out how many are needed to fill it, then write the number sentence. Work on simple "change unknown" problems (e.g., 5 + □ = 12).', 'hands-on', '["Egg cartons","Small objects","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 25, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('1eb47b63-4ec0-4351-8a48-6b73cba3ff81', 'mathematics', '1', 'Operations with Numbers', '1.1', 26, 'Subtraction Terminology Practice', 'Link the terms "take away" and "minus" when writing subtraction equations. Use phrases such as "the difference between" to help compare quantities.', 'hands-on', '["Vocabulary cards","Counters","Whiteboard"]'::jsonb, NULL, NULL, 15, 'individual', 26, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('3e58d63c-349f-4ba2-90e4-822080ec562d', 'mathematics', '1', 'Operations with Numbers', '1.1', 27, 'Number Grid Subtraction Dice Game', 'Use number grid with coloured counter - place counter on called number, roll die to subtract, move counter back. Practice counting back strategy.', 'game', '["Number grid","Counters","Die"]'::jsonb, NULL, NULL, 20, 'individual', 27, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('48843426-4f0c-4ccd-904e-69cc8e4686b8', 'mathematics', '1', 'Operations with Numbers', '1.1', 28, 'Number Bonds to Ten Video', 'Watch "Number Bonds to Ten Song" - I Know My Number Bonds 10 (Jack Hartmann). Sing along and practice number bonds through music.', 'technology', '["Video player/screen","Internet access"]'::jsonb, NULL, NULL, 10, 'individual', 28, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('5a2af6d0-6e66-4798-9bc2-31639fff4cdd', 'mathematics', '1', 'Operations with Numbers', '1.2', 1, 'Count and Combine Objects', 'Count and combine objects into different groups and move them around to find the answer. Show the part + part = whole using small objects to practice solving problems.', 'hands-on', '["Counters","Small objects","Sorting mats"]'::jsonb, NULL, NULL, 20, 'individual', 1, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('57a0fd50-4539-440f-89f6-ff87e684c5df', 'mathematics', '1', 'Operations with Numbers', '1.2', 2, 'Bowling Pin Subtraction', 'Set up 20 bowling pins (or cups) and use a ball to knock some down. Record subtraction equations to represent what is left standing (i.e., 20 pins – ? = ?).', 'game', '["20 plastic cups or pins","Soft ball","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 2, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('b08b709f-cd93-4473-92ad-b131e5f6ee02', 'mathematics', '1', 'Operations with Numbers', '1.2', 3, 'Decomposing Numbers', 'Practice decomposing whole numbers into various parts using concrete objects and record using symbols. Represent number sentences after decomposing using numerals and symbols.', 'hands-on', '["Counters","Number bond templates","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('559b51b8-c127-4aaf-90f0-393c8bd15f12', 'mathematics', '1', 'Operations with Numbers', '1.2', 4, 'Concrete to Symbolic Progression', 'Use concrete models (blocks), drawings, and then symbols (numbers) to represent number facts. Progress from manipulatives to pictorial to abstract representations.', 'hands-on', '["Blocks","Drawing paper","Number cards","Symbol cards (+, -, =)"]'::jsonb, NULL, NULL, 25, 'individual', 4, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('aad4d283-e34d-4383-ba49-52943db14437', 'mathematics', '1', 'Operations with Numbers', '1.2', 5, 'Storyboard Recording', 'Use storyboards to add/subtract items and record results. Students create visual stories then translate to number sentences.', 'hands-on', '["Storyboard templates","Small objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 5, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('d48cdad5-4b46-45d4-9780-dc1cfaec2f55', 'mathematics', '1', 'Operations with Numbers', '1.2', 6, 'Set to Symbol Matching', 'Match the set to its number symbol. Students connect quantities to their numeric representation.', 'hands-on', '["Object sets","Number cards","Matching worksheets"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('8f654bc5-eca4-431d-ad4e-2fc275ed225d', 'mathematics', '1', 'Operations with Numbers', '1.2', 7, 'Addition Symbol Discussion', 'Class discussion on the symbol (+) of addition. Teacher demonstrates/prompts as students come up with their own words that tell (+) addition.', 'hands-on', '["Large + symbol card","Vocabulary chart","Markers"]'::jsonb, NULL, NULL, 15, 'individual', 7, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('14c308d9-ef0b-4235-8b05-553ed96d5ca8', 'mathematics', '1', 'Operations with Numbers', '1.2', 8, 'Symbolic Representation Cards', 'In small groups, give cards or manipulatives to write symbolic representation of what is on the card or what they made. Transfer pictorial to symbolic representation.', 'hands-on', '["Picture cards","Manipulatives","Whiteboards","Markers"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('33c73867-090a-42cc-a0d1-883ffd9c043f', 'mathematics', '1', 'Operations with Numbers', '1.2', 9, 'Write the Number Symbol', 'Write the number (symbol) to the set/group shown. Use symbols to represent the pictures shown on worksheets.', 'hands-on', '["Picture worksheets","Pencils"]'::jsonb, NULL, NULL, 15, 'individual', 9, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('7acf63c5-f8d0-4410-8c8d-501d5ba8c7d4', 'mathematics', '1', 'Operations with Numbers', '1.2', 10, 'Dice Symbolic Representation', 'In pairs, small groups or whole class - roll two dice, then write symbolic representations showing additive thinking. Record equations like 3 + 5 = 8.', 'game', '["Dice (pair)","Recording sheets","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('48a7aec5-a7d7-48d4-ad97-72530ccf6bde', 'mathematics', '1', 'Operations with Numbers', '1.2', 11, 'Draw and Match Activity', 'Draw any amount of objects in circles then write the correct number symbol to match. Self-evaluation activity.', 'hands-on', '["Drawing paper","Crayons","Number cards"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('f6a11081-ed3a-4cd8-8940-3c98d24b3086', 'mathematics', '1', 'Operations with Numbers', '1.2', 12, 'Extension: Numbers Beyond 20', 'Challenge activity: Students needing extension move to numbers greater than 20 (e.g., show 23 + 17 =). Match pictorial to symbolic representation.', 'hands-on', '["Base ten blocks","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 12, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('2cccdbc2-8c8e-4358-90a6-c7b20e8f9730', 'mathematics', '1', 'Operations with Numbers', '1.2', 13, 'Language Integration: Number Sentences', 'Language/Reading integration: Write sentences about pictures with numbers (e.g., "Mum has ___ bananas"). Include number names during vocabulary lessons (zero to twenty).', 'hands-on', '["Picture cards","Writing paper","Vocabulary word wall"]'::jsonb, NULL, NULL, 25, 'individual', 13, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('614650f8-7118-4062-95f0-1f705547068f', 'mathematics', '1', 'Operations with Numbers', '1.2', 14, 'Social Studies: Family Numbers', 'Social Science integration: Draw family and different family types, write number for total family members. Connect math to real-life contexts.', 'hands-on', '["Drawing paper","Crayons","Family templates"]'::jsonb, NULL, NULL, 25, 'individual', 14, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('70b6cf4d-893f-4748-9399-571669b80435', 'mathematics', '1', 'Operations with Numbers', '1.2', 15, 'Science: Body Parts Counting', 'Science integration: Draw and write numbers for body parts (toes, eyes, ears, fingers, nose). Extension: "All of your fingers + all of your best friends fingers."', 'hands-on', '["Body outline templates","Crayons","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 15, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('3482708f-75e3-489e-90a1-6749dd320bd6', 'mathematics', '1', 'Operations with Numbers', '1.3', 1, 'Equal Groups Exploration', 'Provide opportunities to work with equal group problems involving three quantities: number of groups, size of each group, and total of all groups. Form groups using 20 objects (advanced learners can exceed 20).', 'hands-on', '["Counters","Sorting mats","Number cards"]'::jsonb, NULL, NULL, 25, 'individual', 1, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('cd84de00-d3d7-4baf-8ad0-e482fd4e1596', 'mathematics', '1', 'Operations with Numbers', '1.3', 2, 'Multiplication as Repeated Addition', 'Make the connection that multiplication and repeated addition produce the same results. Examples: 1 × 3 means add 3 one time; 2 × 3 means add 3 two times (2 × 3 = 3 + 3 = 6); 3 × 2 means add 2 three times (3 × 2 = 2 + 2 + 2 = 6).', 'hands-on', '["Counters","Recording sheets","Multiplication symbol cards"]'::jsonb, NULL, NULL, 25, 'individual', 2, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('aad2970a-2745-4a60-bde3-8d3b52e1efea', 'mathematics', '1', 'Operations with Numbers', '1.3', 3, 'Story Problems with Multiplication', 'Write story problems using the multiplication sign and explain what the two factors mean. Example: 4 × 8 refers to 4 sets of 8.', 'hands-on', '["Story problem templates","Counters","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 3, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('ab70bb1a-2791-4a34-9a21-c94e684ab865', 'mathematics', '1', 'Operations with Numbers', '1.3', 4, 'Building Groups with Manipulatives', 'Use manipulatives to build groups (e.g., group 20 objects into 2s, 3s, 4s...10s). Count the number of groups formed and the total number of objects used. Remaining objects that dont form a complete group can be placed aside.', 'hands-on', '["Counters","Sorting mats","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 4, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('b6486259-c4e5-43cd-8d49-b7cdf7fb3bde', 'mathematics', '1', 'Operations with Numbers', '1.3', 5, 'Skip Count and Record', 'Example: 20 objects into groups of 3s = 6 groups of 3, skip count to find total of 18. Write mathematical statements: 3+3+3+3+3+3 = 18; "six groups of three make 18".', 'hands-on', '["Counters","Skip counting charts","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('9aeb2703-2f8b-4323-a8d9-63ecfeabb1be', 'mathematics', '1', 'Operations with Numbers', '1.3', 6, 'Equal Groups Video', 'Watch YouTube video on grouping objects and writing repeated addition equations. "Show Equal Groups with Repeated Addition" video.', 'technology', '["Video player/screen","Internet access"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('70b7e31f-b67a-454b-9db4-035b40101be7', 'mathematics', '1', 'Operations with Numbers', '1.3', 7, 'Multiplication as Repeated Addition Video', 'Watch "Multiplication as Repeated Addition" video (goes up to 40, can pause to suit grade level). Students observe and practice along.', 'technology', '["Video player/screen","Internet access"]'::jsonb, NULL, NULL, 15, 'individual', 7, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('433248b3-b1b0-4262-8feb-377803577b82', 'mathematics', '1', 'Operations with Numbers', '1.3', 8, 'Picture Skip Counting', 'Count items in pictures and skip count to find totals. Skip count to find the total of each grouping shown on worksheets.', 'hands-on', '["Picture worksheets","Skip counting strips"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('d239a63d-642e-4e9d-9d3e-2f51fe499c5b', 'mathematics', '1', 'Operations with Numbers', '1.3', 9, 'Array Building', 'In small groups, use objects to form arrays. Example: Make 3 groups of 4 - place 3 objects in a row, fill each row with 3 additional objects until 3 rows with 4 objects each. Skip count the total and write mathematical statement: 4+4+4=12, "three groups of 4 make 12".', 'hands-on', '["Counters","Grid mats","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 9, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('427bd8da-98d3-4880-b156-c60d0442a452', 'mathematics', '1', 'Operations with Numbers', '1.3', 10, 'Musical Chairs Grouping Game', 'Teacher rolls die and calls out a number for grouping. Music starts, students form groups of that number before music ends. Students not in a group when music ends are out. After each grouping: count students in group, number of groups in class, and total.', 'movement', '["Music player","Die","Open space"]'::jsonb, NULL, NULL, 25, 'individual', 10, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('11253a63-42a2-4153-a2c6-ee2f2fba6b67', 'mathematics', '1', 'Operations with Numbers', '1.3', 11, 'Equal Sharing Discovery', 'Place learners in pairs with even number of items. Discover how many ways items can be shared equally (e.g., 20 items: 2s, 4s, 5s, 10s). Fill out cards for each equal group made.', 'hands-on', '["Counters","Recording cards","Sorting mats"]'::jsonb, NULL, NULL, 25, 'individual', 11, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('fca2f0ab-fdac-4ce1-94d0-442ee63515ad', 'mathematics', '1', 'Operations with Numbers', '1.3', 12, 'Fair Sharing (Partition Division)', 'Solve problems where group size is unknown. Example: "John has 20 apples. He wants to give equal shares to his 4 friends. How many apples will each friend receive?" Students use manipulatives to solve.', 'hands-on', '["Counters","Sorting mats","Story cards"]'::jsonb, NULL, NULL, 25, 'individual', 12, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('60c6c7d9-3251-4164-bd2f-ae27e08e201d', 'mathematics', '1', 'Operations with Numbers', '1.3', 13, 'Repeated Subtraction Division', 'Solve problems where number of groups is unknown but size is known. Example: "John has 20 apples. He put them into bags containing 5 apples each. How many bags did John use?"', 'hands-on', '["Counters","Paper bags or sorting containers","Story cards"]'::jsonb, NULL, NULL, 25, 'individual', 13, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('77edd356-4e4b-4ff3-8fa9-da52ba431240', 'mathematics', '1', 'Operations with Numbers', '1.3', 14, 'Division Mathematical Statements', 'Write mathematical statements to represent division. Example: "20 counters shared into 5s give 4 groups". Circle groups of items equally on activity sheets.', 'hands-on', '["Activity worksheets","Counters","Crayons"]'::jsonb, NULL, NULL, 20, 'individual', 14, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('3b0403bf-4433-4127-b332-b95c5baf6fdb', 'mathematics', '1', 'Operations with Numbers', '1.3', 15, 'Group Counting and Recording', 'Write total number of groups in each case. Count total items, say how many groups formed when shared. Example: "2 bears shared into 2s is 1 group".', 'hands-on', '["Counting bears","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 15, '2026-01-06T09:54:22.323395+00:00', '2026-01-06T09:54:22.323395+00:00'),
  ('ea92274e-f575-49e8-8d96-a7bfa72e1d81', 'mathematics', '1', 'Patterns and Relationships', '1.1', 1, 'Pattern Song Introduction', 'Allow learners to listen/view and participate in a pattern song. At the end of the video, pose questions at various cognitive levels to help learners recall, describe/explain, reproduce and extend the pattern.', 'video', '["Computer/tablet","Projector","Pattern song video (https://rb.gy/fc8q)"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('bdf27f61-167e-4436-a415-9d5a21ca0786', 'mathematics', '1', 'Patterns and Relationships', '1.1', 2, 'Pattern Video Discussion', 'After watching pattern video, ask questions like: "What did you observe about the cars in the video? How do you call what you observed?" Encourage learners to describe patterns they noticed.', 'discussion', '["Pattern video","Whiteboard"]'::jsonb, NULL, NULL, 10, 'individual', 2, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('b4b4cddd-7d12-47c3-84dd-e8456f80704b', 'mathematics', '1', 'Patterns and Relationships', '1.1', 3, 'Cut-out Pattern Activity', 'In pairs, learners use their cut-outs or cars to demonstrate their solutions to questions being asked. Arrange cars in the order they appeared in the video. Identify which car came first, which came after the red car.', 'hands-on', '["Car cut-outs","Colored paper","Scissors"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('8851a417-75e6-45b2-a6d9-4b4652aa2ba4', 'mathematics', '1', 'Patterns and Relationships', '1.1', 4, 'Pattern Prediction', 'Students predict which car/object will come next based on pattern arrangements. Teacher guides discussion about pattern rules and extensions.', 'hands-on', '["Cut-outs","Pattern cards","Objects for sequencing"]'::jsonb, NULL, NULL, 15, 'individual', 4, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('3e25212d-3bc2-4c51-8067-609ddc44ce41', 'mathematics', '1', 'Patterns and Relationships', '1.1', 5, 'Pattern Core Identification', 'Look at the pattern core and identify terms: "Each car is called a term. How many terms are in the pattern core?" Identify the rule of the pattern from the pattern core.', 'hands-on', '["Pattern strips","Objects for patterns","Whiteboard"]'::jsonb, NULL, NULL, 15, 'individual', 5, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('1ae384e0-560d-435e-8527-731b616af295', 'mathematics', '1', 'Patterns and Relationships', '1.1', 6, 'Extending Patterns', 'Follow the rule and make the pattern longer using cut-outs. Find different ways to extend the pattern (can extend from any direction). Identify which element is missing and explain how they knew.', 'hands-on', '["Cut-outs","Pattern blocks","Counters"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('6a48b27d-6cbc-42a3-9d04-1cc9b2bc8c8e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 7, 'Exploring Patterns - Think, Pair, Share', 'Provide opportunities to explore, create and talk about repeating patterns with two, three, and four-element cores progressively. In pairs or small groups, rotate through different activity centers to create patterns. Share creations with partner/group members.', 'discussion', '["Various manipulatives","Pattern cards","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 7, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('55b7ac0d-23ef-4511-a173-0a00aed6b524', 'mathematics', '1', 'Patterns and Relationships', '1.1', 8, 'Pattern Questioning', 'Ask questions to help conceptualize characteristics of a repeating pattern: "Can you show me your pattern core?" "How many elements make up your pattern core?" "How are you sure that you have a pattern?" "Can you extend your pattern?"', 'discussion', '["Student-created patterns","Discussion prompts"]'::jsonb, NULL, NULL, 15, 'individual', 8, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('0bcf4feb-b930-4887-83a6-56c53bab74bd', 'mathematics', '1', 'Patterns and Relationships', '1.1', 9, 'Manipulative Center - Pattern Creation', 'Use natural and found materials to create patterns: leaves, sticks, pebbles, sea shells, building blocks, toys including soft toys, slices of plantains/potatoes, cotton buds.', 'hands-on', '["Leaves","Sticks","Pebbles","Sea shells","Building blocks","Toys","Cotton buds"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('e3288433-44b8-4ff5-957d-b2b28e35723e', 'mathematics', '1', 'Patterns and Relationships', '1.1', 10, 'Art Center - Pattern Printing', 'Create patterns using art materials: water, paint, stones, different drawing materials, sponges, leaves, pebbles. Print patterns using stamps made from natural materials.', 'art', '["Paint","Water","Sponges","Leaves","Stones","Drawing materials","Paper"]'::jsonb, NULL, NULL, 25, 'individual', 10, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('2abfc1f0-619f-464b-968b-59c68ef6b2ba', 'mathematics', '1', 'Patterns and Relationships', '1.1', 11, 'Music Center - Sound Patterns', 'Create sound patterns using tins, bottle spoons, wooden sticks, shak-shak (homemade rattles). Students create and repeat rhythmic patterns.', 'song', '["Tins","Bottle spoons","Wooden sticks","Shak-shak (homemade rattles)","Drums"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('cb796719-a315-4511-9103-13de3d75c2ce', 'mathematics', '1', 'Patterns and Relationships', '1.1', 12, 'Physical Education Center - Movement Patterns', 'Use students'' own body movements to create patterns. Use pictures of different body movements to sequence and create patterns.', 'movement', '["Open space","Pictures of body movements","Music (optional)"]'::jsonb, NULL, NULL, 20, 'individual', 12, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('b9068af4-7b64-4166-9a7a-c48c4eded415', 'mathematics', '1', 'Patterns and Relationships', '1.1', 13, 'AB Pattern Creation', 'Create patterns using ABABAB format (2 elements in the core). Practice with various materials and discuss the pattern rule.', 'hands-on', '["Counters","Blocks","Pattern strips"]'::jsonb, NULL, NULL, 15, 'individual', 13, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('a5b75709-0afd-49d9-88cb-5c47ae0e546c', 'mathematics', '1', 'Patterns and Relationships', '1.1', 14, 'ABC Pattern Creation', 'Create patterns using ABCABCABC format (3 elements in the core). Extend to patterns containing up to four element cores (ABCD ABCD ABCD format).', 'hands-on', '["Counters","Blocks","Pattern strips","Various manipulatives"]'::jsonb, NULL, NULL, 20, 'individual', 14, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('56905d18-5ce9-4ce6-bea6-d0d03b9a68fe', 'mathematics', '1', 'Geometrical Thinking', '1.1', 6, 'Geoboard Shape Creation', 'Have students use rubber bands to create shapes on geoboard. Explore different shapes and their properties.', 'hands-on', '["Geoboards","Rubber bands"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('d950d382-70c2-4be3-8b87-aed2c834fb1d', 'mathematics', '1', 'Patterns and Relationships', '1.1', 15, 'Pattern Translation Circle', 'Gather children around a physical circle with different types of materials. Direct attention to a repeating AB letter pattern on cardboard in the center. Reproduce the pattern and demonstrate sound and movement patterns that match.', 'hands-on', '["Cardboard with letter patterns","Various manipulatives","Open space"]'::jsonb, NULL, NULL, 20, 'individual', 15, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('0cf830f8-a6e3-415d-8c94-74a06d7c160b', 'mathematics', '1', 'Patterns and Relationships', '1.1', 16, 'Multi-Modal Pattern Translation', 'Create and translate patterns from one form/mode to another: Body parts to words (foot foot hand), Action to shapes (stump stump snap), Letters to objects/shapes (AAB AAB AAB). Lead learners to see that attributes can change without changing structure.', 'hands-on', '["Letter cards","Shape cards","Objects","Open space"]'::jsonb, NULL, NULL, 25, 'individual', 16, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('6acf5de2-5789-464b-88b1-7c5a5ae2ce34', 'mathematics', '1', 'Patterns and Relationships', '1.1', 17, 'Talking Circles - Pattern Translation', 'Students explore patterns, change attributes and engage in translating them in circles. Discuss observations and share with each other. Use actions, letters, and physical objects to create repeating patterns.', 'discussion', '["Chairs arranged in circle","Pattern materials"]'::jsonb, NULL, NULL, 20, 'individual', 17, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('e44918b0-7260-4781-9148-3463daaf81a4', 'mathematics', '1', 'Patterns and Relationships', '1.1', 18, 'Choral Pattern Chanting', 'One group sings/chants a pattern (ABCABCABC). Other group responds/translates by saying/singing their selected pattern (hop jump skip hop jump skip). Practice with formats: ABABAB, AABAABAAB, etc.', 'song', '["Pattern cards","Open space"]'::jsonb, NULL, NULL, 15, 'individual', 18, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('065698d7-04a9-4da5-8207-e2eb9f8749c3', 'mathematics', '1', 'Patterns and Relationships', '1.1', 19, 'Robocop Error Spotting', 'Invite learners to take on the role of Robocop to spot errors in patterns. Present a sequence of objects, drawings or pictures to pairs/small groups. Learners put on "Robocop hats" before beginning the activity.', 'game', '["Pattern sequences with errors","Robocop hats (paper)","Objects for patterns"]'::jsonb, NULL, NULL, 20, 'individual', 19, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('4370196d-28fe-447f-b2a8-af3b1006ff22', 'mathematics', '1', 'Patterns and Relationships', '1.1', 20, 'Error Analysis Discussion', 'Study the arrangement of objects and answer: "What do you observe?" "Does it show a pattern?" "Can you describe the rule?" "Is there any object that does not belong?" Work in pairs to spot and correct errors, share thinking with partners.', 'discussion', '["Pattern cards with/without errors","Whiteboard"]'::jsonb, NULL, NULL, 15, 'individual', 20, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('149d1458-ddd8-410f-8356-4f66134595d9', 'mathematics', '1', 'Patterns and Relationships', '1.1', 21, 'Border Pattern Creation', 'Create border patterns in groups with 2-4 elements in the core for their desks. Source items from home to create patterns. Given 3 shapes, create borders with shapes arranged differently for each desk.', 'art', '["Paper strips","Colored paper","Glue","Scissors","Items from home/environment"]'::jsonb, NULL, NULL, 30, 'individual', 21, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('dfd0d209-42d3-442e-a082-37ed11e9261f', 'mathematics', '1', 'Patterns and Relationships', '1.2', 1, 'Increasing Pattern Body Movements', 'Learners listen to a chant by the teacher and demonstrate body movements to reflect a given increasing pattern (ABBABBABB). Use physical movements, steps, hand movements or full body movements (e.g., up down down).', 'movement', '["Open space","Pattern chant cards"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('4825fc29-86cb-4cc9-8366-717107a99bbb', 'mathematics', '1', 'Patterns and Relationships', '1.2', 2, 'Pattern Movement Reflection', 'Reflect using guiding questions: "What did you notice while you were doing the actions?" "Can you tell me what action we should do next?" "Are you sure this is what comes next? Why?" "Can you continue the pattern?"', 'discussion', '["Whiteboard","Pattern cards"]'::jsonb, NULL, NULL, 10, 'individual', 2, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('8fd3dd1e-f16a-4236-b7ef-c9f07bfb58d8', 'mathematics', '1', 'Patterns and Relationships', '1.2', 3, 'Growing Pattern with Blocks', 'Present learners with a sequence made out of blocks, bottle caps or physical objects showing increasing pattern (ABABBABBB). Discussion: "What do you notice?" "Is there a pattern?" "What comes next? Why?"', 'hands-on', '["Blocks","Bottle caps","Counters","Physical objects"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('342da6d5-7070-444f-9fe9-602512a6033b', 'mathematics', '1', 'Patterns and Relationships', '1.2', 4, 'Creating Own Growing Patterns', 'After extending the pattern, create a sequence reflecting their own pattern using coloured blocks, bottle caps, emoticons or physical objects.', 'hands-on', '["Coloured blocks","Bottle caps","Emoticon cards","Various objects"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('13644a16-4157-4960-a15c-84f2c38b812c', 'mathematics', '1', 'Patterns and Relationships', '1.2', 5, 'Peter''s Missing Buttons Story', 'Listen to the story about Peter''s Missing Buttons where shirts have increasing buttons (1, 2, 3, 4, 5). Ask questions: "How many buttons do you think will be on the third shirt, 4th shirt, 5th shirt?" Extension: "If Peter had pulled out shirt number 10, how many buttons?"', 'discussion', '["Story script","Button cut-outs","Shirt drawings"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('0846e6a5-66d0-4bdd-931c-0e7841955370', 'mathematics', '1', 'Patterns and Relationships', '1.2', 6, 'Visualizing the Button Story', 'Draw or use objects representing the 5 shirts based on what was heard. Explain the patterns observed in the story.', 'hands-on', '["Paper","Crayons","Button counters","Shirt templates"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('a493eee9-84ff-4f1c-91f4-6c4bc95eb92a', 'mathematics', '1', 'Patterns and Relationships', '1.2', 7, 'Drawing Growing/Decreasing Patterns', 'Draw, paint, create an increasing or decreasing pattern by 1 or 2 elements. Use patterned sponges or leaves or items found in the environment.', 'art', '["Paper","Paint","Sponges","Leaves","Drawing materials"]'::jsonb, NULL, NULL, 25, 'individual', 7, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('7c98b1a2-6001-4fda-9857-6ed68c9b6bc6', 'mathematics', '1', 'Patterns and Relationships', '1.2', 8, 'Manipulative Growing Patterns', 'Demonstrate growing/increasing/decreasing patterns using cut outs, bottle caps, blocks or cubes. Build patterns that grow by 1 or 2 each time.', 'hands-on', '["Cut-outs","Bottle caps","Blocks","Cubes"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('6fe22562-60d8-4c5c-865f-d0ace3e38717', 'mathematics', '1', 'Patterns and Relationships', '1.2', 9, 'Growing Pattern Error Analysis', 'Present students with patterned sequences to analyze. Determine whether patterns follow a given sequence. Spot errors and give reasons why an error exists.', 'hands-on', '["Pattern sequence cards","Manipulatives"]'::jsonb, NULL, NULL, 15, 'individual', 9, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('0925e6fb-89ae-4f78-9425-e0423c155952', 'mathematics', '1', 'Patterns and Relationships', '1.2', 10, 'Error Correction Discussion', 'Determine what needs to be changed or adjusted in the sequence. Guided questions: "Is there a pattern?" "Does the pattern continue in a sequence?" "Can you identify the element that is missing?" "Can you fix the error?"', 'discussion', '["Error pattern cards","Whiteboard","Manipulatives for struggling students"]'::jsonb, NULL, NULL, 15, 'individual', 10, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('64f05a15-d490-4795-9065-591c38548386', 'mathematics', '1', 'Patterns and Relationships', '2.1', 1, 'Building Towers with Connecting Cubes', 'Present learners with a set of connecting cubes. Ask students to build a tower of six, then build a tower of two cubes. Question students: "How many more or fewer?" (e.g., "4 more to make 9").', 'hands-on', '["Connecting cubes","Unifix cubes"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('03a406cd-6949-4931-86e3-5c8b9c13aef8', 'mathematics', '1', 'Patterns and Relationships', '2.1', 2, 'Part-Part-Whole with Number Frames', 'Provide opportunities to use materials to represent Part-Part-Whole relationships. Use Five Frames and Ten Frames to model unknowns. Give students number frames with some coloured counters.', 'hands-on', '["Five frames","Ten frames","Two-colour counters"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('d6b9d71e-a156-44f9-9d3f-f016ebd9fd83', 'mathematics', '1', 'Patterns and Relationships', '2.1', 3, 'Number Frame Questioning', 'Question students about the number of counters and how many more are missing to form the quantity. As students share responses, model using different coloured counters and place the missing part. Example: "This ten-frame has 6 counters. How many more are missing to make 10?"', 'discussion', '["Ten frames","Counters","Whiteboard"]'::jsonb, NULL, NULL, 15, 'individual', 3, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('2f45b470-988b-4ef7-922d-6a83f618f0b8', 'mathematics', '1', 'Patterns and Relationships', '2.1', 4, 'Box Diagrams for Unknowns', 'Use a box diagram as alternative strategy (e.g., 7 = 3 + ?). Draw box diagrams to represent part-part-whole relationships with unknowns.', 'hands-on', '["Paper","Pencils","Box diagram templates"]'::jsonb, NULL, NULL, 15, 'individual', 4, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('5fd44818-5969-446e-933f-460e9585b528', 'mathematics', '1', 'Patterns and Relationships', '2.1', 5, 'Number Lines for Unknowns', 'Use number lines to show unknown numbers. Visualize unknowns on number lines by jumping forward or backward.', 'hands-on', '["Number lines","Counters","Dry erase markers"]'::jsonb, NULL, NULL, 15, 'individual', 5, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('430c789c-055f-4aa0-8a08-2d767470bce4', 'mathematics', '1', 'Patterns and Relationships', '2.1', 6, 'Story Problems - Result Unknown', 'Listen to or read stories involving join, separate, part-part-whole and comparing problem structures. Example: "Sam has 8 sweets. Gina gave him some more. Sam now has 10 sweets. How many sweets did Gina give to Sam?" (8 + ____ = 10)', 'hands-on', '["Story problem cards","Counters","Whiteboard"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('a0b9a44f-4a41-4a2b-a571-fce0b6463ca7', 'mathematics', '1', 'Patterns and Relationships', '2.1', 7, 'Story Problems - Start Unknown', 'Solve stories where the starting amount is unknown. Example: "Sam has some sweets. Gina gave him 2 sweets. Sam now has 10 sweets. How many sweets did Sam have at first?" (____ + 2 = 10)', 'hands-on', '["Story problem cards","Counters","Manipulatives"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('fe257bab-0d66-498e-8463-a52ca951ec33', 'mathematics', '1', 'Patterns and Relationships', '2.1', 8, 'Mental Math Starters', 'Relate situations where students use manipulatives or drawings to represent situations. Examples: "I think of a number. I added 3, I now have 7. What number did I think of?" "My number is 8. I subtract a certain number from it, I now have 4. What number did I subtract?"', 'game', '["Number cards","Counters","Whiteboards"]'::jsonb, NULL, NULL, 15, 'individual', 8, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('1dff91eb-7284-4efb-97b5-54923e4f8e88', 'mathematics', '1', 'Patterns and Relationships', '2.1', 9, 'Joining and Separating with Drawings', 'Represent the unknown using joining and separating situations using drawings/pictures. Examples: 4 + 3 = _____, 4 - ____ = 3, ____ - 1 = 3', 'hands-on', '["Paper","Crayons","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('cf94442b-4515-4320-8b6e-78328d32e895', 'mathematics', '1', 'Patterns and Relationships', '2.1', 10, 'Finding Unknowns with Inverse Operations', 'Find unknown quantities using the inverse of the operation. Use concrete materials and pictorial representations. Examples: 5 + ___ = 6 → 6 - 5 = ____, ____ - 3 = 4 → 4 + 3 = ____', 'hands-on', '["Counters","Number lines","Inverse operation cards"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('4917b022-a01f-4b77-8820-d4ef4ee631b5', 'mathematics', '1', 'Patterns and Relationships', '2.2', 1, 'Number Combinations Song', 'View a video on number combinations with the sum of ten and sing along (https://youtu.be/n2Nfez2e67k?t=65). Apply the same rhythm and melody to other number combinations made for other sums.', 'video', '["Computer/tablet","Projector","Video link"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('20fca5a0-b09a-4453-af4d-338f6176e710', 'mathematics', '1', 'Patterns and Relationships', '2.2', 2, 'Classifying Equal Lengths', 'Classify objects based on equal lengths (building blocks, strips, strings, etc.). Given a pair of lengths, make them equal to each other.', 'hands-on', '["Building blocks","Paper strips","Strings","Rulers"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('1187ecc3-db54-4bbc-a16c-ae65634a8662', 'mathematics', '1', 'Patterns and Relationships', '2.2', 3, 'Creating Equal Lengths', 'Use objects to create equal lengths (string equal lengths of beads, stack equal lengths of blocks). Match equal lengths using letters assigned to each length on a grid (e.g., D = F).', 'hands-on', '["Beads","String","Blocks","Grid paper"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('74153883-d11d-4709-8e68-4501b7d048ce', 'mathematics', '1', 'Patterns and Relationships', '2.2', 4, 'Building Equivalent Lengths', 'In pairs, create equal lengths using building blocks for given lengths. Stack blocks one at a time keeping in mind the previous number. Add blocks to shorter length or remove blocks from longer length to make equivalent.', 'hands-on', '["Building blocks","Unifix cubes"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('c561971e-5818-4e12-9ccc-77322a4e40fe', 'mathematics', '1', 'Patterns and Relationships', '2.2', 5, 'Domino Equal Combinations', 'Solve stories involving equal number combinations. Example: "Mary needs to find all the dominoes in the case with combinations adding up to 8. Which dominoes must she take?"', 'hands-on', '["Dominoes","Story problem cards"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('cd82c543-981c-464d-9fdf-1a88f375a6d1', 'mathematics', '1', 'Patterns and Relationships', '2.2', 6, 'Card Equal Combinations', 'Example: "Jane has to make other equal combinations of cards of a given suit. She is given 2 of hearts and 5 of hearts. What combinations will Jane make?"', 'hands-on', '["Playing cards","Story problem cards"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('7f4c4c8d-2e76-4191-9558-6f1b3ed43815', 'mathematics', '1', 'Patterns and Relationships', '2.2', 7, 'Creating Number Combinations', 'In small groups, create different number combinations for a given example. Follow illustrated patterns to explain equivalent combinations created. Examples for 5: 5 and 0 make 5, 3 and 2 make 5, 4 and 1 make 5.', 'hands-on', '["Counters","Number cards","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('9f093963-78f2-47a6-8133-a17ec2216800', 'mathematics', '1', 'Patterns and Relationships', '2.2', 8, 'Playing Card Equivalence', 'Create other number combinations equal to a given number combination using playing cards. Use guess and check method to make equivalent playing card combinations. In groups, discuss and compare responses.', 'game', '["Playing cards","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('485c4636-ebc7-4d4e-b2fb-ce8953f6c466', 'mathematics', '1', 'Patterns and Relationships', '2.2', 9, 'Money Equivalence Problem', 'Example: "Mark has 2 five-dollar notes. Sue has 1 five-dollar note and 3 one-dollar coins. How much more money does Sue need to make the two amounts equal?" Complete diagrams to make amounts equal.', 'hands-on', '["Play money","Diagrams","Whiteboard"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('8f7247c5-a841-48b7-b451-a36d1bfe57ae', 'mathematics', '1', 'Geometrical Thinking', '1.1', 7, 'Solid Figure Construction', 'Have students use cut outs to make solid figures. Students use given solid figures and make a completely new object.', 'hands-on', '["Paper cut-outs","Nets for 3D shapes","Scissors","Glue"]'::jsonb, NULL, NULL, 25, 'individual', 7, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('1af7c935-9727-4f36-a4d7-87abd675635f', 'mathematics', '1', 'Patterns and Relationships', '2.2', 10, 'Number Line Equivalence', 'Use number lines to create equivalent combinations. Complete combinations for given combinations on number lines. Compare three given number lines to identify pairs showing equal number combinations.', 'hands-on', '["Number lines","Dry erase markers","Counters"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('fb62232f-a06d-4eb0-b378-8568822fb93e', 'mathematics', '1', 'Patterns and Relationships', '2.2', 11, 'Dominoes - Odd One Out', 'Given a set of dominoes, find the "odd one out". State reasons for choosing equal number combinations. State reasons for not choosing the domino that doesn''t belong.', 'game', '["Dominoes","Recording sheets"]'::jsonb, NULL, NULL, 15, 'individual', 11, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('006b430d-ae91-4ac9-9482-1b094898b220', 'mathematics', '1', 'Patterns and Relationships', '2.2', 12, 'True or False Equivalence', 'Analyze pairs of number combinations and check true or false for equality. Discuss how to make non-equivalent combinations equal to others.', 'hands-on', '["Number combination cards","True/False cards"]'::jsonb, NULL, NULL, 15, 'individual', 12, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('ce5c6532-b412-43f4-9b0d-3b2130349ffb', 'mathematics', '1', 'Patterns and Relationships', '2.3', 1, 'Pan Balance Equations', 'Use pan balance or arm balance to understand the concept of a balanced equation. Manipulate coloured counters of equal size to form as many equations as possible. Stick an "=" sign in the middle of the balance.', 'hands-on', '["Pan balance/arm balance","Coloured counters","Equal sign cards"]'::jsonb, NULL, NULL, 20, 'individual', 1, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('1ad87b1c-46c7-440e-8552-21f7d1133ac1', 'mathematics', '1', 'Patterns and Relationships', '2.3', 2, 'Number Bonds for Equations', 'Use number bonds to develop understanding of commutative property of addition (2 + 3 = 3 + 2). Understand part-part-whole relationship of numbers.', 'hands-on', '["Number bond mats","Counters","Number cards"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('7fc07e39-5a76-4a6b-af33-241a470acef5', 'mathematics', '1', 'Patterns and Relationships', '2.3', 3, 'Concrete to Abstract Equations', 'Use counters and cards to make connection from concrete to abstract when forming equations.', 'hands-on', '["Counters","Number cards","Operation cards"]'::jsonb, NULL, NULL, 15, 'individual', 3, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('2a573cd8-1158-4714-b1f6-14e1921a13cb', 'mathematics', '1', 'Patterns and Relationships', '2.3', 4, 'Block Tower Equations', 'Use stackable blocks of different colours (same size) to form equations. Form two stacks with eight blocks each. Manipulate stacks with different colours to form different equations using fact families. Examples: 7 + 1 = 8, 3 + 5 = 8, 6 + 2 = 8.', 'hands-on', '["Stackable blocks (two colours)","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('7510fd71-0bc8-4a23-b77c-c944e2af6668', 'mathematics', '1', 'Patterns and Relationships', '2.3', 5, 'Frame Equations', 'Master the use of 5 frames then use 10 frames to formulate number sentences. Manipulate frames to formulate as many equations as possible.', 'hands-on', '["Five frames","Ten frames","Counters","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('b2e3a9b1-3fdf-4f82-b831-9266d9801ab5', 'mathematics', '1', 'Patterns and Relationships', '2.3', 6, 'Number Sentence Circle Game', 'Pull chairs/desks in a physical circle. Teacher calls out (or writes) three numbers. Students formulate a number sentence using all three numbers. First person to answer gets to hold a ball. Ball passes to next person who answers correctly.', 'game', '["Ball","Number cards","Chairs arranged in circle"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('720717ce-66bc-4fda-af32-b591b7863817', 'mathematics', '1', 'Patterns and Relationships', '2.3', 7, 'Fishing for Equations', 'Play fishing games in small groups to collect numbers that make number sentences true. Discuss what is needed to make number sentences true and why.', 'game', '["Number fish cards","Fishing rods (magnets)","Paper clips"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('8ed28285-10e2-4d0d-a39e-68ffc31b6b8d', 'mathematics', '1', 'Patterns and Relationships', '2.3', 8, 'Dominoes Equation Game', 'Play a game of dominoes and formulate number sentences while playing.', 'game', '["Dominoes","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('0d6a0327-165b-44ee-b709-6028ae3d1d71', 'mathematics', '1', 'Patterns and Relationships', '2.3', 9, 'True or False Number Sentences', 'Give learners cards with number sentences. Determine which ones are true or false.', 'hands-on', '["Number sentence cards","True/False sorting mats"]'::jsonb, NULL, NULL, 15, 'individual', 9, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('daadeb34-40fd-4665-807c-ed8c093c2cfd', 'mathematics', '1', 'Patterns and Relationships', '2.3', 10, 'Unknowns at Different Positions', 'Encourage divergent thinking by writing equations with unknown at varying positions: Simple: 12 = 7 + __, 5 + 7 = __, __ + 5 = 12. Complex: 9 + 1 = 3 + __, __ + __ = 3 + 4, 9 + 1 = __ + 4.', 'hands-on', '["Equation cards","Whiteboards","Counters"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('ef8dfd5f-e0cd-42f2-9dda-b2bacce62081', 'mathematics', '1', 'Patterns and Relationships', '2.3', 11, 'Matching Stories to Equations', 'Give learners two sets of cards: one with number sentences, one with word problems/stories. Engage in cooperative learning to match cards correctly. Examples: "Janai had 12 apples. She ate 3 of them. How many apples does she have left?" → 12 - 3 = 9', 'game', '["Story cards","Equation cards"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('af8d8e3a-72eb-4276-9ef6-42d49d158fd3', 'mathematics', '1', 'Patterns and Relationships', '2.3', 12, 'Creating Stories for Equations', 'Create own stories/scenarios/word problems for given equations. Practice reversible thinking by going from equation to story.', 'hands-on', '["Equation cards","Paper","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 12, '2026-01-06T10:39:29.436838+00:00', '2026-01-06T10:39:29.436838+00:00'),
  ('61e64db4-3a25-4fbc-8744-c08d19b8fa68', 'mathematics', '1', 'Geometrical Thinking', '1.1', 1, 'Real-World Shape Examples', 'Use real-world examples to help students understand shape characteristics and properties. Show students a cube-shaped box or a cylindrical can to understand properties of a cube and cylinder.', 'hands-on', '["Cube-shaped boxes","Cylindrical cans","Various 3D objects from environment"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('0d578fb1-a990-4408-b0a8-a5cf18ae4462', 'mathematics', '1', 'Geometrical Thinking', '1.1', 2, 'Shape Story - Author''s Chair', 'Allow students to create their own story about shapes and use the author''s chair to tell their story to the class.', 'discussion', '["Author''s chair","Shape props","Story planning sheets"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('c4320b2c-84b3-41e8-bc4b-9e96ee4dc9b6', 'mathematics', '1', 'Geometrical Thinking', '1.1', 3, 'Caribbean Shape Story - Sunny the Fish', 'Use the Caribbean story about Sunny the fish who explores the coral reef finding shapes like cylindrical seashells and pentagon-shaped starfish. Discuss the shapes found in the story and relate to local environment.', 'discussion', '["Story script","Shape pictures","Caribbean sea life images"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('91264722-c568-4354-86ce-4792552826e4', 'mathematics', '1', 'Geometrical Thinking', '1.1', 4, 'Shape Making with String and Wire', 'Use string or craft wire to create shapes. Students bend and form materials to make 2D shape outlines.', 'hands-on', '["String","Craft wire","Pipe cleaners"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('34ac0366-b408-496b-96cc-80ad2ce52d40', 'mathematics', '1', 'Geometrical Thinking', '1.1', 5, 'Building 2D and 3D Shapes', 'Use ice lollies, matchsticks, pipe cleaners, playdough to make 2D and 3D shapes. Students construct shapes using various materials.', 'hands-on', '["Ice lolly sticks","Matchsticks","Pipe cleaners","Playdough"]'::jsonb, NULL, NULL, 25, 'individual', 5, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('b52f987c-1b1f-4b8a-b06b-e4a7907695c1', 'mathematics', '1', 'Geometrical Thinking', '1.1', 8, 'Shape Collage', 'Students make a collage with different shapes and materials. Trace the sides and faces of shapes with their fingers before creating.', 'art', '["Construction paper","Magazines","Glue","Scissors","Various materials"]'::jsonb, NULL, NULL, 30, 'individual', 8, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('b0ebff8d-17ea-4a8a-aacc-5dba51828eda', 'mathematics', '1', 'Geometrical Thinking', '1.1', 9, '2D vs 3D Shape Discussion', 'Have students identify the relationship between 2D and 3D shapes. Questions: "What are the differences between 2D and 3D shapes?" "How many 2D shapes combine to make this 3D shape?" "Is a shadow 2D or 3D?"', 'discussion', '["2D shape cards","3D objects","Flashlight for shadows"]'::jsonb, NULL, NULL, 15, 'individual', 9, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2e5a57c6-aeb6-4666-a2fa-a737b561020c', 'mathematics', '1', 'Geometrical Thinking', '1.1', 10, 'Shape Word Search', 'Provide students with properties and they must find the name of shapes in a word search puzzle.', 'game', '["Word search puzzles","Pencils"]'::jsonb, NULL, NULL, 15, 'individual', 10, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('d0511c90-2178-4f94-9ad8-cd568764c161', 'mathematics', '1', 'Geometrical Thinking', '1.1', 11, 'School Shape Walk', 'Engage students in a shape walk to identify different shapes in their school/community/church/recreation areas. Have students identify a shape and state the uses of it in real life setting.', 'movement', '["Clipboards","Recording sheets","Pencils"]'::jsonb, NULL, NULL, 30, 'individual', 11, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('79b3e70e-5485-42ab-acaf-d51f974a3333', 'mathematics', '1', 'Geometrical Thinking', '1.1', 12, 'Nature Shape Hunt', 'Take students on a nature walk and ask them to find shapes in the environment (circles in tree trunks, triangles in leaves). Describe the shapes found and possible purpose of the shape. Use positional language.', 'movement', '["Outdoor space","Recording sheets","Pencils","Cameras (optional)"]'::jsonb, NULL, NULL, 30, 'individual', 12, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('f4b296a6-68f9-443e-80f8-3e77675ad6de', 'mathematics', '1', 'Geometrical Thinking', '1.1', 13, 'Shape Interview', 'Have students interview each other about the missing shape. Provide opportunities for students to recall facts about properties of shapes.', 'discussion', '["Interview question cards","Shape cards"]'::jsonb, NULL, NULL, 15, 'individual', 13, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('639d9154-88bb-44a0-9903-70df9ce75469', 'mathematics', '1', 'Geometrical Thinking', '1.1', 14, 'My Shape Book', 'Have students make a shape book which includes the shape, properties about the shape, and where it can be found in the environment.', 'art', '["Paper","Crayons","Magazines","Scissors","Glue","Stapler"]'::jsonb, NULL, NULL, 30, 'individual', 14, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('64b4932a-ab59-47bd-bac9-b8c93a42923c', 'mathematics', '1', 'Geometrical Thinking', '1.1', 15, 'Virtual Museum Tours', 'Use VR technology or virtual tours to immerse students in 3D environments. Explore museums, historical landmarks, and real-world spaces to identify shapes.', 'technology', '["Computer/tablet","Internet access","Virtual tour links"]'::jsonb, NULL, NULL, 25, 'individual', 15, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('f9c803c8-d405-455b-8ecb-2f06eacf06a9', 'mathematics', '1', 'Geometrical Thinking', '1.1', 16, 'Digital Geoboard Game', 'Use digital geoboard to create and manipulate different shapes. Students explore shape properties through interactive app.', 'technology', '["Tablets/computers","Geoboard app (mathlearningcenter.org)"]'::jsonb, NULL, NULL, 20, 'individual', 16, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('8ae8a76e-e7ab-482e-baf2-df3fe1a26f8c', 'mathematics', '1', 'Geometrical Thinking', '1.1', 17, 'Tangram Digital Game', 'Use tangram pieces to recreate different shapes and objects using digital tangram app.', 'technology', '["Tablets/computers","Tangram app (coolmathgames.com)"]'::jsonb, NULL, NULL, 20, 'individual', 17, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('1ff95591-e02b-4ba2-9cf8-57ec803d865d', 'mathematics', '1', 'Geometrical Thinking', '1.1', 18, 'Shape Maze Activity', 'Provide students with a simple maze and ask them to find the path that leads to a specific shape. Describe the shapes seen in the maze and use positional language to describe location.', 'hands-on', '["Maze worksheets","Pencils","Crayons"]'::jsonb, NULL, NULL, 15, 'individual', 18, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('fed29335-910e-4ac1-8d04-891dac102578', 'mathematics', '1', 'Geometrical Thinking', '1.1', 19, 'Shape Transformations', 'Provide students with a set of 2D shapes and ask them to transform them into different shapes (e.g., cutting a square to make two triangles). Use positional language and gestures to describe the changes made.', 'hands-on', '["Paper shapes","Scissors","Glue"]'::jsonb, NULL, NULL, 25, 'individual', 19, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('3552d8cc-3f74-4dc4-9f10-abcf572f1c17', 'mathematics', '1', 'Geometrical Thinking', '1.1', 20, 'Shape Transformation Game', 'Provide students with cards showing different shapes undergoing transformation (stretching, shrinking). Describe the changes and use positional language to describe location of shapes.', 'game', '["Transformation cards","Shape manipulatives"]'::jsonb, NULL, NULL, 20, 'individual', 20, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('36fe5414-c0aa-42e1-9020-b843b9212729', 'mathematics', '1', 'Geometrical Thinking', '1.1', 21, 'Transformation Shape Book', 'Create a transformation shape book showing geometric shapes before and after transformation.', 'art', '["Paper","Crayons","Scissors","Stapler"]'::jsonb, NULL, NULL, 30, 'individual', 21, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('541dd6fd-1c11-400e-a429-6911895db00e', 'mathematics', '1', 'Geometrical Thinking', '1.1', 22, 'Design a Shape Maze', 'Students design their own maze to find shapes. Include various shapes along the path.', 'art', '["Paper","Pencils","Rulers","Crayons"]'::jsonb, NULL, NULL, 25, 'individual', 22, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('e3216195-dcb8-48b4-9791-0f1aadad61ec', 'mathematics', '1', 'Geometrical Thinking', '1.1', 23, 'Shape Video Project', 'Students create a video highlighting shapes found in their environment.', 'technology', '["Tablets/phones","Video editing app (optional)"]'::jsonb, NULL, NULL, 30, 'individual', 23, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('cabbbe85-f764-4a56-a501-0db563ed5e48', 'mathematics', '1', 'Geometrical Thinking', '1.2', 1, 'Shape is Right Game', 'Modification of The Price is Right: Place properties on screen and students must name the correct shape and state the attributes.', 'game', '["Shape property cards","Whiteboard/projector"]'::jsonb, NULL, NULL, 20, 'individual', 1, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('90a094f2-f27d-4c28-9fad-1154adc8538d', 'mathematics', '1', 'Geometrical Thinking', '1.2', 2, 'Wheel of Fortune Shapes', 'Spin the wheel and speak about the shape the needle points to. Students describe properties and give examples.', 'game', '["Spinning wheel with shapes","Shape cards"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('51bd496b-3cf0-4d8d-8ed9-62fd94dd421e', 'mathematics', '1', 'Geometrical Thinking', '1.2', 3, 'Musical Shapes', 'Play Musical Chairs and Old Grady on shapes so students'' ability to identify and name shapes is highlighted.', 'game', '["Shape floor mats","Music player"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('647beea0-8bfc-4079-ad42-95ea141b5c41', 'mathematics', '1', 'Geometrical Thinking', '1.2', 4, 'Mystery Bag of Shapes', 'Students are blindfolded, choose a shape from the mystery bag, then give a description of the chosen shape without looking.', 'game', '["Mystery bag","3D shapes","Blindfolds"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('d0c079e3-75b1-45be-be75-97deca435f2c', 'mathematics', '1', 'Geometrical Thinking', '1.2', 5, 'Drawing 2D and 3D Shapes', 'Allow students to draw 2D and 3D shapes. Focus on accurate representation of properties.', 'art', '["Paper","Pencils","Crayons","Rulers"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('08b5b09d-ac5f-4d2e-bddb-4ff97b437b6f', 'mathematics', '1', 'Geometrical Thinking', '1.2', 6, 'Favorite Shape Poster', 'Create a poster on their favorite shape. Create a poster to advertise their favourite shape and its properties.', 'art', '["Poster board","Markers","Shape stencils","Magazines"]'::jsonb, NULL, NULL, 30, 'individual', 6, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('790d2f9f-3dfc-44c1-b450-7778c31089f5', 'mathematics', '1', 'Geometrical Thinking', '1.2', 7, 'Compound Shape Creation', 'Use one or more shapes to construct a compound shape. Draw a shape using a variety of plane shapes.', 'art', '["Paper","Crayons","Shape templates"]'::jsonb, NULL, NULL, 25, 'individual', 7, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('e67fbfcf-7323-4259-9b40-a7fb4205be9b', 'mathematics', '1', 'Geometrical Thinking', '1.2', 8, 'Sand Tracing Shapes', 'Have students trace their fingers on 2D shapes made from sand to identify sides and corners.', 'hands-on', '["Sand trays","Shape templates"]'::jsonb, NULL, NULL, 15, 'individual', 8, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('f00358e3-8ca6-4d2c-8b4d-895ead3b2402', 'mathematics', '1', 'Geometrical Thinking', '1.2', 9, 'Rolling and Stacking Investigation', 'Allow students to manipulate shapes to deduce those that roll and stack. Provide with toy ramp for experimentation.', 'hands-on', '["3D shapes","Toy ramp","Recording sheet"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('ef836d0c-92d2-4f02-b385-aed72fb9c7eb', 'mathematics', '1', 'Geometrical Thinking', '1.2', 10, 'Geoboard Shape Making', 'Students use geoboard to make geometric shapes. Explore properties through hands-on manipulation.', 'hands-on', '["Geoboards","Rubber bands"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('0e56a679-e3a4-42e0-bc7f-6be877ed65da', 'mathematics', '1', 'Geometrical Thinking', '1.2', 11, '2D and 3D Relationship Discussion', 'Have students identify the relationship between a 2D and 3D shape. Discuss how 2D shapes make up faces of 3D objects.', 'discussion', '["2D shapes","3D objects","Whiteboard"]'::jsonb, NULL, NULL, 15, 'individual', 11, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('5fcbad69-28bc-4095-9828-0ce2e3e8458a', 'mathematics', '1', 'Geometrical Thinking', '1.2', 12, 'Tiered Shape Activities', 'Tier 1: Justify the shape appropriateness for its usage in real life. Tier 2: State the properties of all shapes. Tier 3: Classify the given shapes based on identified attributes.', 'hands-on', '["Shape manipulatives","Property cards","Sorting mats"]'::jsonb, NULL, NULL, 25, 'individual', 12, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('0f9d83ad-65ba-41f0-9e8b-81680a67cc84', 'mathematics', '1', 'Geometrical Thinking', '1.2', 13, 'Geometric Art Project', 'Assign groups to create a piece of art using geometric shapes (2D drawing or 3D sculpture). Encourages creativity, visual-spatial skills, and collaboration.', 'art', '["Various art materials","Construction paper","Clay","Glue"]'::jsonb, NULL, NULL, 35, 'individual', 13, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('593d26d6-56e3-40f0-be9d-895343453dc4', 'mathematics', '1', 'Geometrical Thinking', '1.2', 14, 'Shape Walk - Real Life Uses', 'Engage students in a shape walk to identify different shapes in their environment. Have students identify a shape and state the uses of it in real life setting.', 'movement', '["Clipboards","Recording sheets","Pencils"]'::jsonb, NULL, NULL, 30, 'individual', 14, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2e571a69-efee-493a-bc6e-0e53205459df', 'mathematics', '1', 'Geometrical Thinking', '1.2', 15, 'Build a City Project', 'Have students work in groups to design and build a city using different shapes. Use cardboard, construction paper, or other materials to create buildings, roads, and structures. Each group presents their city describing shapes used.', 'hands-on', '["Cardboard","Construction paper","Scissors","Glue","Markers"]'::jsonb, NULL, NULL, 45, 'individual', 15, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('1e4a8a41-8412-4795-a80a-268389183ce2', 'mathematics', '1', 'Geometrical Thinking', '1.2', 16, '3D Object Investigation', 'Provide students with a collection of 3D objects (cube, cone, sphere, cylinder). Investigate and identify different characteristics of each object (number of faces, edges, corners). Draw and label each object in their learning log.', 'hands-on', '["3D shape sets","Learning logs","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 16, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('ba18a577-10ba-449e-9225-fba3bda7b3fa', 'mathematics', '1', 'Geometrical Thinking', '1.2', 17, 'Shape Exhibition', 'Select a 2D or 3D shape and students bring objects from home that reveal their shape. Students make a collage with different shapes and materials.', 'hands-on', '["Objects from home","Display area","Labels"]'::jsonb, NULL, NULL, 30, 'individual', 17, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('cf754695-4125-4a5e-af7e-fa8592b838a7', 'mathematics', '1', 'Geometrical Thinking', '1.2', 18, 'Shape Exploration Inquiry', 'Start with a question: "What shapes do you see around you every day?" Provide variety of materials (pattern blocks, wooden shapes). Sort and group shapes based on attributes. Record observations and discuss findings.', 'hands-on', '["Pattern blocks","Wooden shapes","Paper shapes","Recording sheets"]'::jsonb, NULL, NULL, 30, 'individual', 18, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('35d15079-d954-42cd-a59a-aad914c96c25', 'mathematics', '1', 'Geometrical Thinking', '1.2', 19, 'Shape Collage Project', 'Collect pictures of objects representing different shapes from magazines, newspapers, online resources. Cut and paste onto poster board.', 'art', '["Magazines","Newspapers","Scissors","Glue","Poster board"]'::jsonb, NULL, NULL, 30, 'individual', 19, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('5f3bf963-3fe0-4196-a77b-8487e4998a85', 'mathematics', '1', 'Geometrical Thinking', '1.2', 20, 'Shape Museum', 'Create a shape museum by designing and creating models of different shapes using clay, playdough, or other materials. Include descriptions of attributes.', 'hands-on', '["Clay","Playdough","Index cards","Display area"]'::jsonb, NULL, NULL, 35, 'individual', 20, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('18460734-95ae-4aec-bf2d-f06bd34c301f', 'mathematics', '1', 'Geometrical Thinking', '2.1', 1, 'Geometry Scavenger Hunt', 'Divide students into small groups. Give each group a list of geometric shapes and objects to find (rectangle, sphere, cone, cube). Find shapes around the classroom or school. Promotes teamwork and observation skills.', 'game', '["Scavenger hunt lists","Clipboards","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 1, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('20e58d7d-2855-4d76-b7c9-ae8f4974fd89', 'mathematics', '1', 'Geometrical Thinking', '2.1', 2, '3D Bingo', 'Students listen to attributes of geometric shapes and match it with the 3D object printed on their bingo card.', 'game', '["Bingo cards with 3D shapes","Attribute cards","Markers"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('449f33f4-5800-4958-8bbd-a438c1680370', 'mathematics', '1', 'Geometrical Thinking', '2.1', 3, 'Wheel of Shapes', 'Names of shapes on large paper with spinner attached. Students spin, identify if shape is 2D or 3D, then state a characteristic.', 'game', '["Spinner wheel","Shape names","Recording sheet"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('30a1c8c2-5359-4d89-b2ac-0a5cc67ea936', 'mathematics', '1', 'Geometrical Thinking', '2.1', 4, 'Online 3D Shape Games', 'Use interactive online games to practice identifying and describing 3D shapes. Sites: SplashLearn, Education.com, Wordwall.', 'technology', '["Tablets/computers","Internet access"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('e8f8f595-45f1-41d3-923c-be89c4524129', 'mathematics', '1', 'Geometrical Thinking', '2.1', 5, 'Solid Figure Making', 'Have students use cut outs to make solid figures. Students use the given solid figures and make a completely new object.', 'hands-on', '["Paper nets","Scissors","Glue","Tape"]'::jsonb, NULL, NULL, 25, 'individual', 5, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2dfbbc3b-4f2d-4205-885c-3b6b2907f33d', 'mathematics', '1', 'Geometrical Thinking', '2.1', 6, 'Shape Tracing', 'Have students trace the sides and faces of shapes with their fingers. Choose a shape and state attributes of shape.', 'hands-on', '["2D and 3D shapes","Recording sheets"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2174c984-3f08-4e0d-b0d0-d4884453f536', 'mathematics', '1', 'Geometrical Thinking', '2.1', 7, 'Roll and Slide Investigation', 'Students are provided with a toy ramp to observe which 3D shapes can roll and which can only slide.', 'hands-on', '["3D shapes","Toy ramp","Recording sheet"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('4d59a111-a923-4885-9f39-fa143b5fc6f2', 'mathematics', '1', 'Geometrical Thinking', '2.1', 8, 'Pattern Block Creations', 'Students work with pattern blocks and create other shapes or objects out of them.', 'hands-on', '["Pattern blocks","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 8, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('7cfadc65-a224-49a7-bc0b-13edfa4f78bf', 'mathematics', '1', 'Geometrical Thinking', '2.1', 9, 'Shape Property Songs', 'Have students write and sing songs about the properties of shapes. Students listen to songs and view clippings on geometric shapes.', 'song', '["Music player","Shape song videos","Paper for lyrics"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('82fbcc55-774f-4399-9536-de897d5b2b10', 'mathematics', '1', 'Geometrical Thinking', '2.1', 10, 'Shape Sorting Activity', 'Divide students into small groups. Provide each group with a set of 2D and 3D shapes. Sort shapes based on specific criteria (shape, color, size, number of sides). Identify similarities and differences.', 'hands-on', '["2D and 3D shapes","Sorting mats","Labels"]'::jsonb, NULL, NULL, 25, 'individual', 10, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('8c79b54c-0ac2-42db-9bf2-4e169d259293', 'mathematics', '1', 'Geometrical Thinking', '2.1', 11, 'Shape Patterning Challenge', 'Provide groups with a set of 2D and/or 3D shapes. Create a repeating pattern using the shapes. Extend by challenging critical thinking skills.', 'hands-on', '["2D shapes","3D shapes","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('9f985019-1f1e-4197-92ab-2e91a8b6c919', 'mathematics', '1', 'Geometrical Thinking', '2.1', 12, 'Digital Shape Drawing', 'Use digital drawing tools (drawing apps, online whiteboard platforms) to create representations of 2D and 3D shapes.', 'technology', '["Tablets/computers","Drawing apps (Tux Paint, Sketch.io)"]'::jsonb, NULL, NULL, 20, 'individual', 12, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('375031cf-f17d-4800-8aa7-83a1e1bbf134', 'mathematics', '1', 'Geometrical Thinking', '2.1', 13, 'Real-World Shape Analysis', 'Provide variety of real-world objects for students to describe solid shapes. Identify and name 2D shapes they can find in given solid shapes. Example: soccer ball used to identify circle (patches) and sphere (overall shape).', 'hands-on', '["Soccer balls","Boxes","Cans","Various objects"]'::jsonb, NULL, NULL, 20, 'individual', 13, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('8d7f998a-89d6-4a3e-8795-a676f0589bd0', 'mathematics', '1', 'Geometrical Thinking', '2.1', 14, 'Design Your Own Shape', 'Students design their own shape using local materials and writing its attributes.', 'hands-on', '["Local materials","Paper","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 14, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('15ec99cf-eb1c-4e55-8d5d-45bec5824a27', 'mathematics', '1', 'Geometrical Thinking', '2.1', 15, 'Shape Poster Collaboration', 'Students work collaboratively to create a shape poster showing various shapes and their attributes.', 'art', '["Poster board","Markers","Shape pictures"]'::jsonb, NULL, NULL, 30, 'individual', 15, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('3f6ceb0f-cace-497c-9bcd-3ab8b0ac2156', 'mathematics', '1', 'Geometrical Thinking', '2.1', 16, 'Finger Paint Shapes', 'Use finger painting to draw shapes. Explore shape properties through tactile art.', 'art', '["Finger paint","Paper","Smocks"]'::jsonb, NULL, NULL, 25, 'individual', 16, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('740d9ae3-a15b-4f94-b164-a8cf8fed4a21', 'mathematics', '1', 'Geometrical Thinking', '2.1', 17, 'Shape Treasure Hunt', 'Treasure hunts involving geometric shapes. Find hidden shapes around the classroom.', 'game', '["Hidden shape cards","Treasure map","Small prizes"]'::jsonb, NULL, NULL, 25, 'individual', 17, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('5021771c-5318-42ff-8c8e-70d6fcc89047', 'mathematics', '1', 'Geometrical Thinking', '2.2', 1, 'Sand Shape Tracing', 'Use fingers to trace shapes in sand. Students feel the shape while naming it.', 'hands-on', '["Sand trays","Shape cards"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('5a118ef9-75ec-41dc-af96-b1ef75301fda', 'mathematics', '1', 'Geometrical Thinking', '2.2', 2, 'Playdough Shape Making', 'Create shapes using playdough. Use hands to feel different faces of a cube. Create 3D objects using playdough.', 'hands-on', '["Playdough","Shape cards","Rolling pins"]'::jsonb, NULL, NULL, 20, 'individual', 2, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('45675cf7-1b0f-419d-89f2-a6660ca54505', 'mathematics', '1', 'Geometrical Thinking', '2.2', 3, 'Interactive Shape Apps', 'Use tablets or interactive whiteboards to engage students in identifying and naming shapes. Use an app that allows tracing shapes or rotating a 3D object on a touchscreen.', 'technology', '["Tablets","Interactive whiteboard","Shape apps"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('04ee28b8-8da6-4853-80b8-70659c89cdaf', 'mathematics', '1', 'Geometrical Thinking', '2.2', 4, 'Shape Attribute Charts', 'Provide students with examples of each shape/object. Have them identify and label the attributes on the charts. Create attribute charts for 2D shapes and 3D objects displaying different attributes.', 'hands-on', '["Attribute chart templates","Shape examples","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 4, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('66997ed9-fe36-408a-81f6-83c567371242', 'mathematics', '1', 'Geometrical Thinking', '2.2', 5, 'Shape Impressions', 'Use shapes to make impressions in playdough. Students identify the shape from its impression.', 'hands-on', '["Playdough","3D shapes","Recording sheets"]'::jsonb, NULL, NULL, 15, 'individual', 5, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('77ecde11-bfbe-417d-aa88-6f0adf7792a8', 'mathematics', '1', 'Geometrical Thinking', '2.2', 6, 'Attribute Matching Game', 'Create a matching game where students match the 2D shape or 3D object with its corresponding attributes. Example: match a square with the attribute "4 sides, 4 angles".', 'game', '["Shape cards","Attribute cards"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2563fe78-7a41-4f8b-b84a-6ce657ea598d', 'mathematics', '1', 'Geometrical Thinking', '2.2', 7, 'Attribute Sorting', 'Provide students with a set of 2D shapes or 3D objects. Sort them into groups based on a specific attribute. Example: sort 2D shapes based on number of sides or 3D objects based on number of faces.', 'hands-on', '["2D shapes","3D objects","Sorting mats"]'::jsonb, NULL, NULL, 20, 'individual', 7, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('7cb9f95e-1f24-49ac-a008-09a49b60a49c', 'mathematics', '1', 'Geometrical Thinking', '2.2', 8, 'Attribute Scavenger Hunt', 'Hide 2D shapes or 3D objects around the classroom or outdoor area. Provide students with a list of attributes to find. Example: "Find an object with 4 sides and 4 angles".', 'game', '["Hidden shapes","Attribute clue cards"]'::jsonb, NULL, NULL, 25, 'individual', 8, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('108c4cb0-da41-457c-9252-3bead1f41d44', 'mathematics', '1', 'Geometrical Thinking', '2.2', 9, 'Shapes in Real Life', 'Provide students with opportunities to see 2D shapes and 3D objects in real-life situations. Identify shapes in the classroom or during a nature walk. Identify 3D objects in their homes.', 'discussion', '["Observation sheets","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('fe4e3c15-db18-4d2a-969c-41784ed87af6', 'mathematics', '1', 'Geometrical Thinking', '2.2', 10, 'Shape Posters and Flashcards', 'Use posters, flashcards, and real-life objects to help students visualize and understand differences between 2D shapes and 3D objects. Use videos and animations to show how shapes look in the real world.', 'discussion', '["Shape posters","Flashcards","Real objects","Videos"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('d22e3ea3-1969-48b0-bc97-5395989f880f', 'mathematics', '1', 'Geometrical Thinking', '2.2', 11, 'Multi-Material Shape Creation', 'Provide variety of materials for students to create 2D shapes and 3D objects (paper, clay, cardboard, blocks). Cater to different learning styles and preferences.', 'hands-on', '["Paper","Clay","Cardboard","Blocks"]'::jsonb, NULL, NULL, 25, 'individual', 11, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('9d78c0c0-f4ce-433f-9b39-2a44232eaf99', 'mathematics', '1', 'Geometrical Thinking', '2.2', 12, 'Shapes in Construction', 'Use pictures of buildings or bridges to show how 3D shapes can be used in construction. Discuss the shapes used and why they were chosen.', 'discussion', '["Pictures of buildings","Pictures of bridges","Discussion questions"]'::jsonb, NULL, NULL, 15, 'individual', 12, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('5eec2cab-f7cd-4fbf-ac5e-22138b0a893e', 'mathematics', '1', 'Geometrical Thinking', '2.3', 1, 'Shape Recognition with Visuals', 'Use pictures, posters, and diagrams to help students recognize and name geometric shapes. Use colorful images that clearly show the shape and label it with its name.', 'discussion', '["Shape posters","Colorful shape images","Labels"]'::jsonb, NULL, NULL, 15, 'individual', 1, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('872a26a3-e176-4365-a4cf-c309d5f99e66', 'mathematics', '1', 'Geometrical Thinking', '2.3', 2, 'Shape Descriptions', 'Provide clear and concise verbal instructions when introducing a new shape. Examples: "A triangle has three straight sides and three angles." "A circle is a round shape with no corners or angles."', 'discussion', '["Shape examples","Description cards"]'::jsonb, NULL, NULL, 15, 'individual', 2, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('6a129db3-99a0-4e10-8d7e-29ffd2614e50', 'mathematics', '1', 'Geometrical Thinking', '2.3', 3, 'Building Shapes with Blocks', 'Build shapes with blocks. Use pattern blocks to make shapes. Manipulate shapes and explore their characteristics.', 'hands-on', '["Building blocks","Pattern blocks"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('fccd782a-37f6-430d-b262-1354f2d63823', 'mathematics', '1', 'Geometrical Thinking', '2.3', 4, 'Shape Identification Games', 'Work together to identify and describe shapes. Play games that involve recognizing shapes.', 'game', '["Shape cards","Game materials"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('fe495a5a-b1c8-4e8a-b015-0e8387a1f1b0', 'mathematics', '1', 'Geometrical Thinking', '2.3', 5, 'Shapes in Nature and Buildings', 'Use real-world examples of geometric shapes to help students understand relevance and application. Point out shapes in buildings or in nature.', 'discussion', '["Pictures","Outdoor observation area"]'::jsonb, NULL, NULL, 20, 'individual', 5, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('57b879e8-23d7-4b3d-95c3-d468b4d65a9a', 'mathematics', '1', 'Geometrical Thinking', '2.3', 6, 'Touch and Feel Shapes', 'Touch and feel the different sides and angles of a shape. Explore shape properties through tactile experience.', 'hands-on', '["Various 2D and 3D shapes","Blindfolds (optional)"]'::jsonb, NULL, NULL, 15, 'individual', 6, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('ba19b471-9840-4713-91de-5a2fa7762dab', 'mathematics', '1', 'Geometrical Thinking', '2.3', 7, '2D Shape Rhyme', 'Use rhymes to help students remember shape properties: "Circle, circle, round and round, No corners or edges to be found. Squares are like a box or tile, Four sides and corners make them smile."', 'song', '["Rhyme posters","Shape visuals"]'::jsonb, NULL, NULL, 15, 'individual', 7, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('d2f0959b-d09d-4a5b-a041-1223e8796600', 'mathematics', '1', 'Geometrical Thinking', '2.3', 8, '3D Shape Rhyme', 'Use rhymes for 3D shapes: "A sphere is like a ball or globe, Round and curvy. A cube has six faces, all the same. A cone has one point and a circle base."', 'song', '["Rhyme posters","3D shape visuals"]'::jsonb, NULL, NULL, 15, 'individual', 8, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('3ee2d33f-6f4b-402c-8de3-70f43db3273a', 'mathematics', '1', 'Geometrical Thinking', '2.3', 9, '2D vs 3D Sorting', 'Show students different 2D and 3D shapes and ask them to name each one. Sort shapes into two categories: 2D shapes and 3D shapes. Place circle, square, triangle, rectangle in "2D shapes" section. Place cube, cylinder, sphere, cone in "3D shapes" section.', 'hands-on', '["2D shapes","3D shapes","Sorting mats","Timer"]'::jsonb, NULL, NULL, 20, 'individual', 9, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('35cc00bf-262a-40c0-8551-92045d6ef3ef', 'mathematics', '1', 'Geometrical Thinking', '2.3', 10, 'Shape Bingo', 'Play shape bingo to reinforce shape recognition and naming.', 'game', '["Bingo cards with shapes","Shape calling cards","Markers"]'::jsonb, NULL, NULL, 20, 'individual', 10, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('78889408-b18b-430b-a60d-17a902a4135d', 'mathematics', '1', 'Geometrical Thinking', '2.3', 11, 'Shape Memory Match', 'Memory matching games with 2D and 3D shapes. Match shapes with their names or attributes.', 'game', '["Memory cards with shapes","Memory cards with names/attributes"]'::jsonb, NULL, NULL, 20, 'individual', 11, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('f704da3f-e8e6-4024-a49f-75ef5b17e2af', 'mathematics', '1', 'Geometrical Thinking', '2.3', 12, 'Shape Pattern Creation', 'Identify and create patterns using geometric shapes. Explore relationships between shapes through patterning.', 'hands-on', '["Various shapes","Pattern strips","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 12, '2026-01-06T10:50:15.198826+00:00', '2026-01-06T10:50:15.198826+00:00'),
  ('2fcb1c37-31d5-46d4-9696-a5c5a768613d', 'mathematics', '1', 'Measurement', '1.1', 1, 'Length and Height Vocabulary', 'Introduce vocabulary for length comparisons: long, longer, longest, short, shorter, shortest, tall, taller, tallest. Use real objects to demonstrate each term and have students practice using the words in sentences.', 'discussion', '["Various objects of different lengths","Vocabulary cards","Chart paper"]'::jsonb, NULL, NULL, 20, 'individual', 1, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('eb2324df-55e9-4e28-8449-a86de66e80ed', 'mathematics', '1', 'Measurement', '1.1', 2, 'Capacity Vocabulary', 'Introduce vocabulary for capacity: full, empty, holds more, holds less. Use containers with water or sand to demonstrate concepts. Students practice filling and emptying containers while using vocabulary.', 'discussion', '["Various containers","Water or sand","Funnels","Vocabulary cards"]'::jsonb, NULL, NULL, 25, 'individual', 2, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('8c732f38-8444-4b7c-a496-0dc2807780d2', 'mathematics', '1', 'Measurement', '1.1', 3, 'Mass/Weight Vocabulary', 'Introduce vocabulary for mass: heavy, heavier, heaviest, light, lighter, lightest. Students hold different objects and describe them using measurement vocabulary.', 'discussion', '["Objects of varying weights","Balance scale","Vocabulary cards"]'::jsonb, NULL, NULL, 20, 'individual', 3, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('5e9f7b70-4948-4bb4-933a-6ac73d14aed9', 'mathematics', '1', 'Measurement', '1.1', 4, 'Area Vocabulary', 'Introduce vocabulary for area: covers more, covers less, same area. Use tiles, leaves, or paper squares to cover surfaces and compare areas.', 'discussion', '["Square tiles","Leaves","Paper squares","Flat surfaces to cover"]'::jsonb, NULL, NULL, 20, 'individual', 4, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('befde6df-4be4-4112-b884-97868a5ca6bf', 'mathematics', '1', 'Measurement', '1.1', 5, 'Caribbean Story: The Longest Fishing Line', 'Tell a story about Caribbean fishermen comparing the length of their fishing lines. Use vocabulary: long, longer, longest. Students act out the story and identify length comparisons.', 'discussion', '["Story props","Rope or string of varying lengths","Fishing net props"]'::jsonb, NULL, NULL, 25, 'individual', 5, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('46107098-c93b-447e-a99c-461d06a5d73e', 'mathematics', '1', 'Measurement', '1.1', 6, 'Caribbean Story: Grandma''s Coconut Water', 'Share a story about Grandma filling containers with coconut water - some full, some empty, some holding more or less. Students identify capacity vocabulary in the story.', 'discussion', '["Story script","Various containers","Pictures of coconut water"]'::jsonb, NULL, NULL, 20, 'individual', 6, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('69d3d96b-456c-49db-b78a-4e3e388967d4', 'mathematics', '1', 'Measurement', '1.1', 7, 'Length Exploration Station', 'Set up stations with objects of varying lengths. Students explore and sort objects by length, using vocabulary: long, short, longer, shorter. Record findings using pictures.', 'hands-on', '["Ribbons","Sticks","Pencils","Crayons","Sorting mats","Recording sheets"]'::jsonb, NULL, NULL, 30, 'individual', 7, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f26305bb-bac1-4c91-9caf-a9e3f03333e5', 'mathematics', '1', 'Measurement', '1.1', 8, 'Capacity Pouring Station', 'Students explore capacity by pouring water or sand between containers. They predict which container holds more before testing, then describe results using vocabulary.', 'hands-on', '["Various containers","Water or sand","Funnels","Trays","Recording sheets"]'::jsonb, NULL, NULL, 30, 'individual', 8, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('863d2ea6-96e6-450e-9689-ea81991513d3', 'mathematics', '1', 'Measurement', '1.1', 9, 'Heavy or Light Exploration', 'Students hold and compare objects to determine which is heavier or lighter. Use balance scale to verify predictions. Describe findings using mass vocabulary.', 'hands-on', '["Various classroom objects","Balance scale","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 9, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('6ba2b441-4fec-442f-801f-1e92b0bddd81', 'mathematics', '1', 'Measurement', '1.1', 10, 'Cover the Shape', 'Students cover flat shapes with tiles or paper squares to explore area concepts. Compare which shapes need more or fewer tiles to cover. Use vocabulary: covers more, covers less.', 'hands-on', '["Square tiles","Paper squares","Various flat shapes","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 10, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f2418c36-5273-46ac-b462-d08290532082', 'mathematics', '1', 'Measurement', '1.1', 11, 'Tall and Short Freeze Dance', 'Play music while students move around. When music stops, teacher calls out "tall" or "short" - students freeze in that position. Extend to longest/shortest by having students line up.', 'movement', '["Music player","Open space"]'::jsonb, NULL, NULL, 15, 'individual', 11, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('91d3b32b-42b0-47b5-ab3d-d56100f39f5f', 'mathematics', '1', 'Measurement', '1.1', 12, 'Measurement Vocabulary Bingo', 'Students play bingo with measurement vocabulary words. Teacher shows objects or pictures, students cover the matching vocabulary word on their card.', 'game', '["Bingo cards with vocabulary words","Objects or pictures","Markers"]'::jsonb, NULL, NULL, 20, 'individual', 12, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f86e2662-3ba9-4a85-8e7b-7d5996d19f6d', 'mathematics', '1', 'Measurement', '1.1', 13, 'Long and Short Song', 'Teach a song about length vocabulary: "Long, longer, longest - watch things grow! Short, shorter, shortest - here we go!" Students use hand motions to show comparisons.', 'song', '["Song lyrics chart","Hand motions guide"]'::jsonb, NULL, NULL, 10, 'individual', 13, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('1de57ca6-163f-411e-9211-412c7e3f402f', 'mathematics', '1', 'Measurement', '1.1', 14, 'Heavy and Light Chant', 'Teach a chant: "Heavy, heavier, heaviest - hard to lift! Light, lighter, lightest - like a gift!" Students act out lifting heavy and light objects.', 'song', '["Chant lyrics chart"]'::jsonb, NULL, NULL, 10, 'individual', 14, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('64d3058b-5d1c-4e46-8234-638137480ba4', 'mathematics', '1', 'Measurement', '1.1', 15, 'Measurement Vocabulary Collage', 'Students create a collage showing measurement vocabulary. Draw or cut out pictures showing: long/short, heavy/light, full/empty, covers more/less. Label with vocabulary words.', 'art', '["Magazines","Scissors","Glue","Construction paper","Markers"]'::jsonb, NULL, NULL, 30, 'individual', 15, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('76761f22-49c6-46b7-94d5-1067158cbc6a', 'mathematics', '1', 'Measurement', '1.2', 1, 'Height Lineup', 'Students compare their heights by standing back-to-back. Order themselves from shortest to tallest. Extend by comparing heights of objects in the classroom.', 'hands-on', '["Open space","Recording chart"]'::jsonb, NULL, NULL, 20, 'individual', 16, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('7fb7683c-be5f-4b33-a0bf-2e624be00378', 'mathematics', '1', 'Measurement', '1.2', 2, 'Length Ordering', 'Provide sets of objects (ribbons, sticks, pencils) for students to order from shortest to longest or longest to shortest. Use comparison vocabulary as they work.', 'hands-on', '["Ribbons of various lengths","Sticks","Pencils","Sorting mats"]'::jsonb, NULL, NULL, 25, 'individual', 17, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('b0857154-836b-44bf-982b-10d806cb4f23', 'mathematics', '1', 'Measurement', '1.2', 3, 'Capacity Comparison Challenge', 'Students compare containers to determine which holds more or less. Order containers from holds least to holds most by pouring and testing.', 'hands-on', '["Various containers","Water or sand","Funnels","Trays"]'::jsonb, NULL, NULL, 30, 'individual', 18, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('a9682314-dd38-4f62-82b3-8325a567a82e', 'mathematics', '1', 'Measurement', '1.2', 4, 'Balance Scale Comparisons', 'Use a balance scale to compare the mass of objects. Students predict which is heavier, then test. Order objects from lightest to heaviest.', 'hands-on', '["Balance scale","Various classroom objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 19, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('0a8c62ec-2679-4275-9a33-8c211551cedd', 'mathematics', '1', 'Measurement', '1.2', 5, 'Caribbean Fruit Comparison', 'Compare and order Caribbean fruits by size: mango, lime, papaya, guinep. Discuss which is longer, heavier, or holds more seeds.', 'hands-on', '["Caribbean fruits (real or pictures)","Balance scale","Comparison charts"]'::jsonb, NULL, NULL, 25, 'individual', 20, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('67e9dbc4-0ab9-4bce-aba2-d001c0783c4d', 'mathematics', '1', 'Measurement', '1.2', 6, 'Caribbean Story: Ordering Fish at Market', 'Tell a story about ordering fish at the market from smallest to largest. Students act out comparing fish and using vocabulary: smaller, larger, longest.', 'discussion', '["Story script","Fish cutouts of various sizes"]'::jsonb, NULL, NULL, 20, 'individual', 21, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f5f543f4-eafc-4c28-9101-690d12808a58', 'mathematics', '1', 'Measurement', '1.2', 7, 'Ordering Relay Race', 'Teams race to order objects from shortest to longest or lightest to heaviest. First team to correctly order their objects wins.', 'game', '["Sets of objects to order","Cones or markers","Open space"]'::jsonb, NULL, NULL, 20, 'individual', 22, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('aff976b4-57d6-43e7-b1e3-fea8293da92f', 'mathematics', '1', 'Measurement', '1.2', 8, 'Guess the Order', 'Teacher displays objects in order. Students close eyes while one object is removed. Students identify which object is missing and where it belongs in the order.', 'game', '["Ordered sets of objects","Covering cloth"]'::jsonb, NULL, NULL, 15, 'individual', 23, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('8ddaad68-5c88-4a26-9659-2fcbf065cf02', 'mathematics', '1', 'Measurement', '1.2', 9, 'Area Comparison', 'Students compare the area of different shapes by covering them with tiles. Record which shape needs more tiles, fewer tiles, or the same number.', 'hands-on', '["Various flat shapes","Square tiles","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 24, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('73906816-1a3d-4a3e-85fb-85ca3ffcc5e7', 'mathematics', '1', 'Measurement', '1.2', 10, 'String Comparison', 'Use string to compare lengths of curved or irregular objects. Lay strings side by side to determine which is longer or shorter.', 'hands-on', '["String","Scissors","Various curved objects"]'::jsonb, NULL, NULL, 20, 'individual', 25, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('485a6415-2c88-48a3-91a9-3dd780305a9c', 'mathematics', '1', 'Measurement', '1.2', 11, 'Human Graph - Height Order', 'Students line up in order from shortest to tallest, creating a human bar graph. Discuss who is taller than whom, who is the tallest, shortest.', 'movement', '["Open space","Camera (optional)"]'::jsonb, NULL, NULL, 15, 'individual', 26, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('6399546a-9951-4c66-b7dc-e5575d80fdc2', 'mathematics', '1', 'Measurement', '1.2', 12, 'Jump Comparison', 'Students jump as far as they can. Compare jump distances using string or markers. Order from shortest to longest jump.', 'movement', '["Open space","String or markers","Measuring area"]'::jsonb, NULL, NULL, 20, 'individual', 27, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('2d2beeba-7087-48ac-9731-ebc5fb19c601', 'mathematics', '1', 'Measurement', '1.3', 1, 'What is a Unit?', 'Introduce the concept of using objects as units to measure. Demonstrate measuring a desk using hand spans, paper clips, and blocks. Discuss why we need units to measure.', 'discussion', '["Paper clips","Blocks","Hand span demonstration"]'::jsonb, NULL, NULL, 20, 'individual', 28, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('01ef577f-85e8-4b3b-a6ac-1bd84d617ffb', 'mathematics', '1', 'Measurement', '1.3', 2, 'Measuring with Paper Clips', 'Students measure classroom objects using paper clips as units. Record: "The book is 5 paper clips long." Compare measurements with partners.', 'hands-on', '["Paper clips","Classroom objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 29, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('96f9f218-f2bd-41f9-85f6-fef5444f0791', 'mathematics', '1', 'Measurement', '1.3', 3, 'Measuring with Cubes', 'Students use linking cubes to measure length. Create cube trains and measure objects. Compare: "My pencil is 6 cubes. Yours is 8 cubes. Yours is longer."', 'hands-on', '["Linking cubes","Objects to measure","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 30, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('855aa3c2-3e7a-4352-aa6f-50cbf6a4a1ac', 'mathematics', '1', 'Measurement', '1.3', 4, 'Hand Span Measurement', 'Students measure objects using their hand spans. Discuss why different students get different measurements for the same object. Introduction to need for standard units.', 'hands-on', '["Various classroom objects","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 31, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('8c58a0f9-d526-4088-8f28-cc800385cf13', 'mathematics', '1', 'Measurement', '1.3', 5, 'Footstep Measurement', 'Students measure the length of the classroom or hallway using footsteps. Compare results and discuss why counts differ.', 'hands-on', '["Open space","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 32, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('b2b90134-310e-41c0-a0fc-4553574735ae', 'mathematics', '1', 'Measurement', '1.3', 6, 'Measuring Capacity with Cups', 'Students measure capacity of containers using small cups as units. Record: "The jug holds 4 cups of water."', 'hands-on', '["Small cups","Various containers","Water","Trays","Recording sheets"]'::jsonb, NULL, NULL, 30, 'individual', 33, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('fbfb5229-fee5-46de-86f0-ca2d119d3302', 'mathematics', '1', 'Measurement', '1.3', 7, 'Scoops and Containers', 'Use scoops to measure how much sand or rice different containers hold. Compare and order containers by capacity.', 'hands-on', '["Scoops","Sand or rice","Various containers","Trays"]'::jsonb, NULL, NULL, 25, 'individual', 34, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('1f82ef6a-28b1-418f-a20b-92086d997a32', 'mathematics', '1', 'Measurement', '1.3', 8, 'Measuring with Cubes - Mass', 'Use a balance scale and linking cubes to measure mass. Record: "The eraser weighs 12 cubes."', 'hands-on', '["Balance scale","Linking cubes","Various objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 35, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('27e5e99b-7f2b-49ff-a1ea-0b2cdcae36c6', 'mathematics', '1', 'Measurement', '1.3', 9, 'Caribbean Seed Measurement', 'Use Caribbean seeds (tamarind seeds, guinep seeds) to measure mass on a balance scale. Connect to local culture.', 'hands-on', '["Balance scale","Caribbean seeds","Various objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 36, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f0d2c1a7-cac5-41a2-8f05-4b6d1ec6bd2e', 'mathematics', '1', 'Measurement', '1.3', 10, 'Measuring Area with Square Tiles', 'Students cover flat shapes with square tiles and count to measure area. Record: "The book cover needs 20 tiles."', 'hands-on', '["Square tiles","Flat shapes and objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 37, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('ed2e695f-631a-4836-beb7-2466759bdf77', 'mathematics', '1', 'Measurement', '1.3', 11, 'Leaf Area Measurement', 'Cover shapes with leaves and count. Compare: "This shape needs 8 leaves. That one needs 12 leaves, so it''s bigger."', 'hands-on', '["Leaves of similar size","Various flat shapes","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 38, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('51e0de24-9956-4800-8f79-514940dd84cb', 'mathematics', '1', 'Measurement', '1.3', 12, 'Measurement Scavenger Hunt', 'Students hunt for objects that measure a specific number of units. "Find something that is 10 paper clips long."', 'game', '["Paper clips","Cubes","Task cards","Recording sheets"]'::jsonb, NULL, NULL, 30, 'individual', 39, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('92303f50-beab-412b-96c7-c18595272d9f', 'mathematics', '1', 'Measurement', '1.3', 13, 'Estimation Station', 'Students estimate how many units an object measures, then check by measuring. Record estimates and actual measurements.', 'game', '["Various measuring units","Objects","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 40, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('497f7d47-82dd-4f63-90bf-973905f761eb', 'mathematics', '1', 'Measurement', '1.4', 1, 'Daily Calendar Routine', 'Daily morning routine using the classroom calendar. Identify the day of the week, date, month, and year. Discuss yesterday, today, and tomorrow.', 'discussion', '["Classroom calendar","Day/date cards","Weather chart"]'::jsonb, NULL, NULL, 15, 'individual', 41, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('3ea765c8-6805-41f4-a82b-8f82dc1e0dfd', 'mathematics', '1', 'Measurement', '1.4', 2, 'Days of the Week Song', 'Sing songs to learn the days of the week in order. Include hand motions and actions for each day.', 'song', '["Song lyrics chart","Day of week cards"]'::jsonb, NULL, NULL, 10, 'individual', 42, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('5d22f926-a82d-4c65-baff-94edd6e9d79a', 'mathematics', '1', 'Measurement', '1.4', 3, 'Months of the Year Song', 'Sing songs to learn the months of the year in order. Connect months to Caribbean celebrations and seasons.', 'song', '["Song lyrics chart","Month cards","Caribbean celebration pictures"]'::jsonb, NULL, NULL, 10, 'individual', 43, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('bf583e08-caa2-4065-ab6b-ebb872f68c22', 'mathematics', '1', 'Measurement', '1.4', 4, 'Birthday Graph', 'Create a class graph of birthdays by month. Discuss which month has the most/fewest birthdays.', 'hands-on', '["Large calendar or graph paper","Birthday markers","Crayons"]'::jsonb, NULL, NULL, 25, 'individual', 44, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('408b676b-6c7c-40c9-b712-4db0b2770f65', 'mathematics', '1', 'Measurement', '1.4', 5, 'Caribbean Holiday Calendar', 'Mark important Caribbean holidays on the calendar. Discuss Carnival, Independence Day, Emancipation Day. Count days until special events.', 'discussion', '["Classroom calendar","Holiday pictures","Event stickers"]'::jsonb, NULL, NULL, 20, 'individual', 45, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('853f48e4-df2c-4dc0-9368-99bf89b8ead5', 'mathematics', '1', 'Measurement', '1.4', 6, 'Introducing the Clock', 'Introduce clock parts: face, numbers, hour hand, minute hand. Students identify parts on demonstration clock and individual clocks.', 'hands-on', '["Demonstration clock","Individual student clocks","Clock parts labels"]'::jsonb, NULL, NULL, 20, 'individual', 46, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('d613c2d8-baaf-4860-955e-1ba264bf44bd', 'mathematics', '1', 'Measurement', '1.4', 7, 'Hour Hand Practice', 'Focus on the hour hand. Students show times to the hour on their clocks: 1 o''clock, 2 o''clock, etc. Read times displayed by teacher.', 'hands-on', '["Student clocks","Time cards","Demonstration clock"]'::jsonb, NULL, NULL, 20, 'individual', 47, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('9196facb-8fca-4a3a-8721-2f8cfd703bed', 'mathematics', '1', 'Measurement', '1.4', 8, 'Half Hour Introduction', 'Introduce half past the hour. Students show and read times: half past 1, half past 2, etc. Discuss where hands point at half past.', 'hands-on', '["Student clocks","Time cards","Demonstration clock"]'::jsonb, NULL, NULL, 20, 'individual', 48, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('53c9d61e-3184-42eb-817f-13d324ca31b9', 'mathematics', '1', 'Measurement', '1.4', 9, 'Daily Schedule', 'Create and discuss the class daily schedule. Match activities to times: "We have reading at 9 o''clock." Students show times on clocks.', 'discussion', '["Daily schedule chart","Student clocks","Activity pictures"]'::jsonb, NULL, NULL, 25, 'individual', 49, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('48fccb4e-63cf-4e74-99e8-35f0e80a1aba', 'mathematics', '1', 'Measurement', '1.4', 10, 'What Time Is It, Mr. Wolf?', 'Play the classic game with time focus. Mr. Wolf calls out times, students take that many steps. Practice telling time through play.', 'game', '["Open space","Demonstration clock (optional)"]'::jsonb, NULL, NULL, 20, 'individual', 50, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('ddd9e740-ddd2-4bb7-944d-1b79d343ee14', 'mathematics', '1', 'Measurement', '1.4', 11, 'Introducing Eastern Caribbean Coins', 'Introduce EC coins: 1 cent, 2 cents, 5 cents, 10 cents, 25 cents. Discuss values, sizes, and features of each coin.', 'discussion', '["EC coins (real or plastic)","Coin posters","Magnifying glasses"]'::jsonb, NULL, NULL, 20, 'individual', 51, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('57ab9dcb-9ade-4fc0-905d-e3df9f7e1a7c', 'mathematics', '1', 'Measurement', '1.4', 12, 'Coin Sorting', 'Students sort coins by value. Create groups of each coin type. Count how many of each coin.', 'hands-on', '["EC coins (real or plastic)","Sorting mats","Counting charts"]'::jsonb, NULL, NULL, 20, 'individual', 52, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('ae90cd86-a5f4-4542-90e7-de82ef039430', 'mathematics', '1', 'Measurement', '1.4', 13, 'Counting Coins', 'Practice skip counting with coins: count by 5s with 5-cent coins, count by 10s with 10-cent coins. Find total values of coin groups.', 'hands-on', '["EC coins","Counting mats","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 53, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('de5f89a4-616a-4fb3-ace5-b9f264fd024c', 'mathematics', '1', 'Measurement', '1.4', 14, 'Classroom Market', 'Set up a classroom market with items priced under $1.00 EC. Students practice paying exact amounts using coins.', 'game', '["Play coins","Market items with price tags","Shopping baskets"]'::jsonb, NULL, NULL, 30, 'individual', 54, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('6c5df490-0e37-4e37-9b66-139bd9e59f25', 'mathematics', '1', 'Measurement', '1.4', 15, 'Coin Rubbing Art', 'Students create coin rubbings with crayons and paper. Identify coins by their imprints. Discuss coin values while creating art.', 'hands-on', '["EC coins","Paper","Crayons"]'::jsonb, NULL, NULL, 25, 'individual', 55, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('351f5986-f418-42ff-a381-6f3c17479a67', 'mathematics', '1', 'Data Handling and Probability', '1.1', 1, 'What is a Question?', 'Introduce the concept of questions that can be answered by collecting information. Distinguish between yes/no questions and questions with many answers.', 'discussion', '["Question word cards","Chart paper","Examples of questions"]'::jsonb, NULL, NULL, 20, 'individual', 56, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('dfa2a2ae-ab44-4160-90b8-0b0b2c5a946f', 'mathematics', '1', 'Data Handling and Probability', '1.1', 2, 'Asking Good Questions', 'Practice creating questions about the class. Model: "What is your favorite fruit?" vs "Do you like fruit?" Discuss which questions get more interesting answers.', 'discussion', '["Question starters chart","Picture prompts"]'::jsonb, NULL, NULL, 20, 'individual', 57, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('e463dea2-cd92-4553-aa00-34e8ce70c0a7', 'mathematics', '1', 'Data Handling and Probability', '1.1', 3, 'Questions About Our Island', 'Generate questions about Caribbean life: favorite local food, favorite beach, how do you get to school? Students suggest questions to ask classmates.', 'discussion', '["Chart paper","Caribbean life pictures","Markers"]'::jsonb, NULL, NULL, 25, 'individual', 58, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('44b0a8a0-31b7-4c6e-ba52-3a88a9b9193a', 'mathematics', '1', 'Data Handling and Probability', '1.1', 4, 'Caribbean Story: Anansi''s Survey', 'Tell a story about Anansi the spider who wanted to learn about his animal friends. Anansi asked questions like "What is your favorite food?" Students help Anansi think of more questions.', 'discussion', '["Anansi story props","Animal pictures","Question cards"]'::jsonb, NULL, NULL, 25, 'individual', 59, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('0537d4dd-1134-492d-ba26-e228b0ff7842', 'mathematics', '1', 'Data Handling and Probability', '1.1', 5, 'Question of the Day', 'Daily routine where students pose and answer a "question of the day." Rotate who asks the question. Collect responses from classmates.', 'hands-on', '["Question of the day chart","Response collection materials"]'::jsonb, NULL, NULL, 15, 'individual', 60, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('2ea8d619-9ee1-4f57-bd41-e4cd76325422', 'mathematics', '1', 'Data Handling and Probability', '1.1', 6, 'Question Cards', 'Students create question cards about topics they want to learn about. Use sentence starters: "What is your favorite...?" "How many...?" "Which do you like better...?"', 'hands-on', '["Index cards","Sentence starters chart","Crayons","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 61, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('192ae023-8df9-4712-8735-b8e84ea29571', 'mathematics', '1', 'Data Handling and Probability', '1.1', 7, 'Partner Question Practice', 'Students work in pairs to practice asking and answering questions. Partners take turns being the questioner and responder.', 'discussion', '["Question prompt cards","Recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 62, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f2563837-1d5a-4ebe-bc2d-e99300b9d600', 'mathematics', '1', 'Data Handling and Probability', '1.1', 8, 'Question Ball Toss', 'Students sit in a circle and toss a ball. Whoever catches it asks a survey question. Class helps refine questions to be clear and answerable.', 'game', '["Soft ball","Open space"]'::jsonb, NULL, NULL, 15, 'individual', 63, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('c40ee2e4-55af-4cce-b1dc-abc4a66b24af', 'mathematics', '1', 'Data Handling and Probability', '1.2', 1, 'What is Data?', 'Introduce the concept of data as information we collect. Show examples of real-world data collection: weather charts, attendance, lunch count.', 'discussion', '["Examples of data displays","Chart paper"]'::jsonb, NULL, NULL, 20, 'individual', 64, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('c4bb5425-d1cb-4901-b940-083588361807', 'mathematics', '1', 'Data Handling and Probability', '1.2', 2, 'Shoe Graph', 'Students sort and graph actual shoes by type (sandals, sneakers, boots). Create a concrete object graph on the floor. Count and compare categories.', 'hands-on', '["Students'' shoes","Floor space","Category labels"]'::jsonb, NULL, NULL, 25, 'individual', 65, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('4176541e-de72-4c03-8c77-ae2bacaa14bc', 'mathematics', '1', 'Data Handling and Probability', '1.2', 3, 'Fruit Graph', 'Collect data on favorite fruits. Students place actual fruits or fruit cutouts in columns to create a graph. Count and compare.', 'hands-on', '["Fruit cutouts or plastic fruits","Graphing mat","Category labels"]'::jsonb, NULL, NULL, 25, 'individual', 66, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('a4e9c641-62b5-4b8a-bebc-c2a86b3abf77', 'mathematics', '1', 'Data Handling and Probability', '1.2', 4, 'Block Graph', 'Students vote by stacking blocks in columns. Each block represents one vote. Topics: favorite color, pet, activity.', 'hands-on', '["Colored blocks or cubes","Graphing mat","Category labels"]'::jsonb, NULL, NULL, 20, 'individual', 67, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('6d011e2e-5a11-4c23-9608-518ed4ceecd0', 'mathematics', '1', 'Data Handling and Probability', '1.2', 5, 'Favorite Pet Pictograph', 'Survey classmates about favorite pets. Create a picture graph using pet stickers or drawings. One picture = one vote.', 'hands-on', '["Pet stickers or stamps","Chart paper","Markers","Survey sheets"]'::jsonb, NULL, NULL, 30, 'individual', 68, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('39fe5085-38e2-4120-a747-7b066efbf462', 'mathematics', '1', 'Data Handling and Probability', '1.2', 6, 'Caribbean Food Pictograph', 'Survey about favorite Caribbean foods: roti, pelau, rice and peas, macaroni pie. Create pictograph with food pictures.', 'hands-on', '["Caribbean food pictures","Chart paper","Glue","Survey sheets"]'::jsonb, NULL, NULL, 30, 'individual', 69, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('67f70a24-d417-478f-b40f-84410c6d2ddc', 'mathematics', '1', 'Data Handling and Probability', '1.2', 7, 'Weather Pictograph', 'Collect daily weather data for a week. Create a picture graph showing sunny, cloudy, rainy days.', 'hands-on', '["Weather symbols","Chart paper","Daily weather observations"]'::jsonb, NULL, NULL, 25, 'individual', 70, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('0ae22b78-070d-4b80-ba7d-462bd2ef76e4', 'mathematics', '1', 'Data Handling and Probability', '1.2', 8, 'Introduction to Tally Marks', 'Teach tally marks for counting: one mark for each, cross after four. Practice counting objects using tallies.', 'hands-on', '["Tally chart templates","Objects to count","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 71, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('cc0d777c-fed0-45a9-b324-f4088311ac48', 'mathematics', '1', 'Data Handling and Probability', '1.2', 9, 'Tally Chart Survey', 'Students conduct surveys using tally charts to record responses. Topics: How did you get to school? What''s your favorite subject?', 'hands-on', '["Tally chart templates","Clipboards","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 72, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('945ebfa1-4c93-4970-a507-b0d54259fc90', 'language-arts', '1', 'Listening and Speaking', '2', 8, 'Show and Tell', 'Regular opportunities for learners to present items and answer questions from classmates.', 'discussion', '["show and tell items"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('77638a44-a519-4d5e-b73d-7c53399b2891', 'mathematics', '1', 'Data Handling and Probability', '1.2', 10, 'Digital Graphing', 'Use online graphing tools to create simple bar graphs or picture graphs. Students input data and see graph created digitally.', 'technology', '["Computer or tablet","Online graphing tool","Data to input"]'::jsonb, NULL, NULL, 30, 'individual', 73, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('84de755d-0601-4ea9-95c2-01008debc32a', 'mathematics', '1', 'Data Handling and Probability', '1.3', 1, 'Data Description Vocabulary', 'Introduce vocabulary for describing data: most, least, fewer, more, same, equal, greater, less. Use graphs to practice vocabulary in context.', 'discussion', '["Vocabulary cards","Sample graphs","Chart paper"]'::jsonb, NULL, NULL, 20, 'individual', 74, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('455860b1-fac9-4590-b776-cf012649f5cd', 'mathematics', '1', 'Data Handling and Probability', '1.3', 2, 'Most and Least', 'Using class graphs, identify which category has the most and which has the least. Use complete sentences: "Red has the most votes. Yellow has the least."', 'discussion', '["Class graphs","Sentence starters"]'::jsonb, NULL, NULL, 15, 'individual', 75, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('3231e312-52d3-4ddb-999e-8d19fc9837ac', 'mathematics', '1', 'Data Handling and Probability', '1.3', 3, 'Graph Description Cards', 'Students receive graph pictures and write or dictate descriptions. Use vocabulary: more than, less than, same as, most, fewest.', 'hands-on', '["Graph pictures","Description cards","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 76, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f6f6aa66-8f69-4b36-92e8-337f95c7ef5a', 'mathematics', '1', 'Data Handling and Probability', '1.3', 4, 'Partner Graph Talk', 'Partners take turns describing graphs to each other. One describes without showing, the other draws based on description. Compare results.', 'discussion', '["Graph pictures","Drawing paper","Crayons"]'::jsonb, NULL, NULL, 25, 'individual', 77, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('0a9f36a8-c98a-4d04-9946-5e47b73529e3', 'mathematics', '1', 'Data Handling and Probability', '1.3', 5, 'Comparison Statements', 'Using class data, students create comparison statements: "More students like dogs than cats." "Fewer students walk to school than ride the bus."', 'hands-on', '["Class graphs","Sentence starters","Writing materials"]'::jsonb, NULL, NULL, 20, 'individual', 78, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('f9512ca7-2769-4f59-ace7-3ec118dea7d5', 'mathematics', '1', 'Data Handling and Probability', '1.3', 6, 'True or False Graph Statements', 'Teacher makes statements about a graph. Students decide if each statement is true or false. Discuss reasoning.', 'game', '["Class graphs","True/False cards or signs"]'::jsonb, NULL, NULL, 15, 'individual', 79, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('67707d88-ded1-46eb-9e85-7b2f3ce557b5', 'mathematics', '1', 'Data Handling and Probability', '1.3', 7, 'Describing Our Island Data', 'Create and describe graphs about Caribbean life: transportation, foods, festivals. Practice using vocabulary to describe patterns.', 'discussion', '["Caribbean-themed graphs","Vocabulary cards"]'::jsonb, NULL, NULL, 25, 'individual', 80, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('66fe2017-eed6-41aa-a4ba-55453bf885f5', 'mathematics', '1', 'Data Handling and Probability', '1.4', 1, 'What Does the Data Tell Us?', 'Discuss what we can learn from graphs. Ask: "If we were planning a party, which food should we serve?" Help students see data informs decisions.', 'discussion', '["Class graphs","Discussion questions"]'::jsonb, NULL, NULL, 20, 'individual', 81, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('2c08f805-e413-4555-bc57-bce9152be8e6', 'mathematics', '1', 'Data Handling and Probability', '1.4', 2, 'Making Predictions', 'Use data to make predictions. "If we surveyed another class, do you think we''d get similar results? Why or why not?"', 'discussion', '["Class graphs","Prediction recording sheets"]'::jsonb, NULL, NULL, 20, 'individual', 82, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('7dd12fdd-07df-4038-84f2-118abf3dc07e', 'mathematics', '1', 'Data Handling and Probability', '1.4', 3, 'Using Data to Solve Problems', 'Present problems that require using graph data. "How many more students like apples than oranges?" Students use graphs to find answers.', 'hands-on', '["Problem cards","Class graphs","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 83, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('d221b5c7-5381-4b5a-8a12-887ef3b3329a', 'mathematics', '1', 'Data Handling and Probability', '1.4', 4, 'Caribbean Story: Market Day Data', 'Share a story about a vendor at the market who uses data to decide what to sell. What did people buy most? What should she bring next week?', 'discussion', '["Story props","Market data examples"]'::jsonb, NULL, NULL, 20, 'individual', 84, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('5fa1457a-fd2b-490a-8047-2070a0b3e7b6', 'mathematics', '1', 'Data Handling and Probability', '1.4', 5, 'Conclusion Cards', 'Students draw conclusions from graphs and record on cards: "I learned that..." "This data shows..." "I think this because..."', 'hands-on', '["Graph pictures","Conclusion card templates","Pencils"]'::jsonb, NULL, NULL, 20, 'individual', 85, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('e2fc0234-4637-470c-9161-e4b43e763513', 'mathematics', '1', 'Data Handling and Probability', '1.4', 6, 'Data Detective', 'Students become "data detectives" who solve mysteries using graphs. Present scenarios and have students use data to draw conclusions.', 'game', '["Mystery scenarios","Related graphs","Detective props (optional)"]'::jsonb, NULL, NULL, 25, 'individual', 86, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('e7e10ed3-adf1-44b9-819d-6c13f91a49d7', 'mathematics', '1', 'Data Handling and Probability', '1.4', 7, 'How Adults Use Data', 'Discuss how adults use data: weather forecasts, sports scores, shopping decisions. Students share examples of data in their lives.', 'discussion', '["Real-world data examples","Picture cards"]'::jsonb, NULL, NULL, 20, 'individual', 87, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('ad67dd8d-336c-4abe-9bb7-babc895bb184', 'mathematics', '1', 'Data Handling and Probability', '1.5', 1, 'Introducing Probability Words', 'Introduce vocabulary: impossible (will never happen), possible (might happen), certain (will definitely happen). Use everyday examples.', 'discussion', '["Vocabulary cards","Example pictures","Chart paper"]'::jsonb, NULL, NULL, 20, 'individual', 88, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('55b2a5c5-5008-4612-88fc-8adc48c760a0', 'mathematics', '1', 'Data Handling and Probability', '1.5', 2, 'Impossible, Possible, or Certain?', 'Discuss examples: "The sun will rise tomorrow" (certain), "It will snow in the Caribbean" (impossible), "I will see a bird today" (possible). Students sort statements.', 'discussion', '["Statement cards","Sorting mat with three columns"]'::jsonb, NULL, NULL, 20, 'individual', 89, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('2281ace7-108e-49d1-9c40-790799eb2114', 'mathematics', '1', 'Data Handling and Probability', '1.5', 3, 'Bag of Cubes', 'Place colored cubes in a bag. If all are red, pulling a red cube is certain. If none are red, it''s impossible. If some are red, it''s possible. Students experiment.', 'hands-on', '["Paper bags","Colored cubes","Recording sheets"]'::jsonb, NULL, NULL, 25, 'individual', 90, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('4baa3566-ba0d-4944-865b-af9e3694a058', 'mathematics', '1', 'Data Handling and Probability', '1.5', 4, 'Spinner Predictions', 'Use spinners with different colored sections. Discuss: "Is it possible to land on blue?" "Is it certain?" "Is it impossible?" Make predictions and test.', 'hands-on', '["Spinners with various colors","Recording sheets","Pencils"]'::jsonb, NULL, NULL, 25, 'individual', 91, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('1af10b88-d3b9-4f8f-a6d8-81fa4bdd95fd', 'mathematics', '1', 'Data Handling and Probability', '1.5', 5, 'Coin Flip Exploration', 'Flip a coin multiple times. Discuss: "Is it possible to get heads?" "Is it certain?" Record results and discuss what we notice.', 'hands-on', '["Coins","Recording sheets","Tally charts"]'::jsonb, NULL, NULL, 20, 'individual', 92, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('48de9e65-9ee1-4e3d-8b83-ba77ce859263', 'mathematics', '1', 'Data Handling and Probability', '1.5', 6, 'Caribbean Probability Examples', 'Discuss probability in Caribbean context: "Will we see the ocean today?" (depends on location), "Will it rain during hurricane season?" (possible), "Will a pelican swim?" (certain).', 'discussion', '["Caribbean life pictures","Statement cards"]'::jsonb, NULL, NULL, 20, 'individual', 93, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('15f8969a-557e-4e4e-9c8e-d17269ee46d7', 'mathematics', '1', 'Data Handling and Probability', '1.5', 7, 'Caribbean Story: Fisherman''s Luck', 'Tell a story about a fisherman who thinks about what fish he might catch. Some fish are certain (common), some possible (sometimes seen), some impossible (don''t live here).', 'discussion', '["Story props","Fish pictures","Probability labels"]'::jsonb, NULL, NULL, 25, 'individual', 94, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('58672537-bef7-4108-ac20-5995db160da8', 'mathematics', '1', 'Data Handling and Probability', '1.5', 8, 'Probability Card Game', 'Create cards with events. Students sort into impossible, possible, or certain. Discuss and debate choices as a class.', 'game', '["Event cards","Three sorting bins or mats"]'::jsonb, NULL, NULL, 20, 'individual', 95, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('da7d512b-cf67-4f37-b57c-ac5b9eb1c6fa', 'mathematics', '1', 'Data Handling and Probability', '1.5', 9, 'Probability Corners', 'Label three corners: Impossible, Possible, Certain. Read statements aloud. Students move to the corner that describes the probability of each event.', 'movement', '["Corner labels","Statement cards","Open space"]'::jsonb, NULL, NULL, 15, 'individual', 96, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('76d39d64-182b-4568-ab31-58a9cc8c1c32', 'mathematics', '1', 'Data Handling and Probability', '1.5', 10, 'Create Your Own Probability', 'Students create situations that are impossible, possible, and certain. Share with partners who must classify each situation.', 'game', '["Recording sheets","Drawing materials"]'::jsonb, NULL, NULL, 25, 'individual', 97, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('ba57f652-c532-4656-9fea-6583b6363e6e', 'mathematics', '1', 'Data Handling and Probability', '1.5', 11, 'Probability Song', 'Teach a simple song: "Impossible means it will never happen, Possible means it might, Certain means it will happen, We''re using probability right!"', 'song', '["Song lyrics chart"]'::jsonb, NULL, NULL, 10, 'individual', 98, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('b50c36e8-77fb-4379-b49f-a7619b76c322', 'mathematics', '1', 'Data Handling and Probability', '1.5', 12, 'Probability Booklet', 'Students create a three-page booklet. Each page shows one probability word with pictures and examples: impossible page, possible page, certain page.', 'art', '["Paper folded into booklets","Crayons","Magazines for pictures","Scissors","Glue"]'::jsonb, NULL, NULL, 30, 'individual', 99, '2026-01-06T12:38:51.991482+00:00', '2026-01-06T12:38:51.991482+00:00'),
  ('93df7f11-d111-4565-8142-7fc2243e9d19', 'science', '1', 'Waves, Light and Sound', '1', 1, 'Sounds Can Be Pleasant to the Ear', 'Show students pictures or actual musical instruments (guitar, drum, oboe) and ask them how the vibration is made.', 'discussion', '["musical instrument pictures","guitar","drum","oboe"]'::jsonb, '["music"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('0360b70d-6845-4809-8c8f-d0f4fdf6f2b0', 'science', '1', 'Waves, Light and Sound', '1', 2, 'Compose a Song or Poem', 'Students compose with the teacher a song or poem about sounds, vibrations, and waves in the environment to practice vocabulary.', 'song', '["chart paper","markers"]'::jsonb, '["language-arts","music"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('4be135c2-6da2-4a9b-a855-b6377c0540b6', 'science', '1', 'Waves, Light and Sound', '1', 3, 'How to Make Sounds With Vibrations', 'Small group experiments identifying how we make things vibrate. Sounds can be made by hitting, plucking, blowing, etc. on different objects and materials.', 'hands-on', '["various objects","rubber bands","drums","bottles"]'::jsonb, NULL, NULL, NULL, 'small-group', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('217d2dc2-9b88-4e04-aeb0-a0821685ff11', 'science', '1', 'Waves, Light and Sound', '1', 4, 'Sound Ordering Activity', 'Students put a group of sounds in order from loudest to softest.', 'hands-on', '["sound recordings","audio player","picture cards"]'::jsonb, NULL, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('5e6b041d-293a-47bd-b4c5-05bb8fa6f71f', 'science', '1', 'Waves, Light and Sound', '1', 5, 'Sound is a Wave: We Can See It!', 'Hold strips of paper or plastic in front of a speaker/radio with volume up, or rest a container of water or hands close to a speaker to observe sound waves.', 'hands-on', '["paper strips","plastic strips","speaker","radio","container of water"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('0d3dca1b-f073-4c47-83f6-3f9453a42f5b', 'science', '1', 'Waves, Light and Sound', '1', 6, 'Musical Instruments Based on Different Vibrations', 'Make a model of a musical instrument and demonstrate its use using everyday materials.', 'art', '["rubber bands","boxes","bottles","string","craft materials"]'::jsonb, '["music","tvet"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('9a81b172-a43d-4cfa-8444-e5c19eddd6c7', 'science', '1', 'Waves, Light and Sound', '1', 7, 'Identifying the Origin of Sounds: Can You Guess What is Vibrating?', 'Play a game to identify, name, and classify materials as metals, wood, plastic, etc. based on the sound produced.', 'game', '["various metal objects","wooden objects","plastic objects"]'::jsonb, NULL, NULL, NULL, 'small-group', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('324153bd-23db-48bc-ba9c-0ca96a893e1c', 'science', '1', 'Waves, Light and Sound', '1', 8, 'Oboe Exploration', 'Students look at a picture of an oboe and learn how the reed (thin piece like grass) creates vibration when blown.', 'discussion', '["oboe picture","grass blades","straws"]'::jsonb, '["music"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('ce9d464a-0528-467e-9159-534be41fd7dc', 'science', '1', 'Waves, Light and Sound', '1', 9, 'Sounds Can Be Dangerous', 'Classroom discussion to identify the danger of loud sounds in our world and how to protect our hearing.', 'discussion', '["ear protection examples","picture cards"]'::jsonb, '["hfle"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('4c556c15-c70a-4703-8b09-b86d73620c81', 'science', '1', 'Waves, Light and Sound', '1', 10, 'What if We Couldn''t Make Sounds?', 'Demonstration with a rubber band (stretch and pluck) and grass between thumbs (blowing), leading to discussion about vocal cords and introduction to sign language.', 'hands-on', '["rubber bands","grass","sign language chart"]'::jsonb, '["hfle","language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('74aa89fe-e611-47db-8421-940b5bba2ad5', 'science', '1', 'Waves, Light and Sound', '2', 1, 'Draw and Cut Light Sources', 'Students draw and cut out sources of light or use light tracers to identify different light sources in their environment.', 'art', '["paper","scissors","crayons","light tracers"]'::jsonb, NULL, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('719efbca-8b76-40b6-8e30-85487411a14d', 'science', '1', 'Waves, Light and Sound', '2', 2, 'Make a Peep Box', 'Construct a peep box to demonstrate that we need light to see things. Students observe how objects become visible when light enters.', 'hands-on', '["shoe box","scissors","small objects","flashlight"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('4421dabf-5829-4de1-98a9-99bc0df377ce', 'science', '1', 'Waves, Light and Sound', '2', 3, 'Natural vs. Artificial Light Sorting', 'Sorting activity where students classify light sources as natural (sun, stars, fire) or artificial (lamps, flashlights, screens).', 'hands-on', '["picture cards of light sources","sorting mats"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('930d997b-12a9-49e8-8088-7667837d666e', 'science', '1', 'Waves, Light and Sound', '2', 4, 'How We See Objects', 'Interactive demonstration showing that light must reflect off objects and enter our eyes for us to see them.', 'hands-on', '["flashlight","mirror","various objects"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('974b6b1b-43ac-4f66-9250-b23ab77409b6', 'science', '1', 'Waves, Light and Sound', '2', 5, 'Light Source Walk', 'Students walk around the school and schoolyard to identify and document different sources of light they encounter.', 'movement', '["clipboard","paper","pencil"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('716e41d5-f9c2-4b3e-8f8e-4f2fefe41f35', 'science', '1', 'Waves, Light and Sound', '3', 1, 'Glass Demonstrations', 'Shine a torch through clear glass, wax paper, and mirrors to demonstrate transparent, translucent, and reflective properties.', 'hands-on', '["torch","clear glass","wax paper","mirrors"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('6eb28f55-bbf4-4858-9668-9cdf20f7b4fe', 'science', '1', 'Waves, Light and Sound', '3', 2, 'Sentence Completion Activity', 'Students complete sentences using proper terminology: "The window is _____ (transparent/translucent) so we can see clearly."', 'worksheet', '["worksheets","pencils"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('701ffbb8-a3b7-4049-bbff-5be7c3186c0e', 'science', '1', 'Waves, Light and Sound', '3', 3, 'Matching Objects to Light Properties', 'Match pictures of objects (windows, mirrors, curtains, wax paper) with the terms: transparent, translucent, reflective, opaque.', 'game', '["picture cards","word cards"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('1558286e-c8cc-4a9f-b485-3df9666199c8', 'science', '1', 'Waves, Light and Sound', '3', 4, 'Rough vs. Smooth Glass Comparison', 'Compare how much light passes through smooth clear glass versus rough/frosted glass. Discuss why bathroom windows are often frosted.', 'hands-on', '["smooth glass","frosted glass","flashlight"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('f8650ce7-5582-4f1b-9c37-088a0de6c702', 'science', '1', 'Waves, Light and Sound', '3', 5, 'Shadow Making Activities', 'Place hands and various objects in front of a light source to create shadows. Explore how opaque objects block light completely.', 'hands-on', '["flashlight","various opaque objects","wall or screen"]'::jsonb, NULL, NULL, NULL, 'individual', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('2c99d142-43d6-47ee-b38a-d1dda4a5e9d6', 'science', '1', 'Waves, Light and Sound', '3', 6, 'Light Seriation Activity', 'Place objects in order from most transparent to most opaque based on how much light passes through them.', 'hands-on', '["various transparent and opaque objects","flashlight"]'::jsonb, '["mathematics"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('af9695db-2e09-4b10-8d11-9a3db6b75298', 'science', '1', 'Waves, Light and Sound', '3', 7, 'School Walk - Light Properties', 'Walk around school identifying objects that are transparent, translucent, reflective, or opaque in different locations.', 'movement', '["clipboard","paper","pencil"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('cc633d7f-8dac-497d-a481-e791841e3270', 'science', '1', 'Waves, Light and Sound', '4', 1, 'Warning Sounds Discussion', 'Discuss warning sounds in the community: car alarms, sirens, church bells, doorbells, animal barking. What messages do they communicate?', 'discussion', '["picture cards","sound recordings"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('867f3e10-4328-4859-9389-4798cf9b58c7', 'science', '1', 'Waves, Light and Sound', '4', 2, 'Animal Communication Videos', 'Watch videos of animals (turkeys, squirrels) communicating with their young. Discuss why and how they use sounds to warn or signal.', 'video', '["projector","screen","internet access"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('708f9061-c1c6-4bd2-aa7d-4e99cf6f83ce', 'science', '1', 'Waves, Light and Sound', '4', 3, 'Make a Siren Sound', 'Students practice making siren sounds and discuss what siren sounds mean (emergency, stay out of the way, someone needs help).', 'movement', NULL, '["hfle"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('cb770ec4-f510-407b-acb7-fca7edfaef2e', 'science', '1', 'Waves, Light and Sound', '4', 4, 'Simple Bell Signal System', 'Create a bell code: 3 strikes = school starting, 1 strike = lunch time, 2 strikes = school over. Students decide signals for recess and emergencies.', 'game', '["bell","chart paper"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('d0fe679c-551d-4f03-98f3-9977d6f6d8c0', 'science', '1', 'Waves, Light and Sound', '4', 5, 'Making Cup-and-String Telephones', 'Construct simple telephones using cups and string. Experiment with different cup sizes and string lengths to see what works best.', 'hands-on', '["plastic cups","string","scissors","tape"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('e12cd401-cbe3-449e-9fed-ea9fcd346371', 'science', '1', 'Waves, Light and Sound', '4', 6, 'Light Communication Challenge', 'Use a torch to send messages using quick/slow on-off flashes. Create codes for: "Come play", "Going to bed", "TV show is on", "Did you eat?"', 'game', '["flashlight","code chart"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('76dafd12-fe39-4496-b8de-040efbc233b4', 'science', '1', 'Waves, Light and Sound', '4', 7, 'Animal Sounds Activity', 'Think of sounds 5 different animals make to communicate messages (fear, hunger, happiness). Practice making those sounds.', 'movement', '["animal picture cards"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('dde991e0-5db3-42fb-bfe1-654ae738a4f7', 'science', '1', 'Waves, Light and Sound', '4', 8, 'Communication Devices Poster', 'Create a picture poster of communication devices developed over the last 100 years: telegraph, lighthouses, Braille, traffic lights, telephones, computers, cell phones.', 'art', '["poster paper","magazines","scissors","glue","markers"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('1b2f5aca-3a1f-4e10-939d-984dee30e0bd', 'science', '1', 'Waves, Light and Sound', '4', 9, 'Traffic Light Discussion', 'Learn what red, yellow, and green lights mean. Discuss how traffic lights help keep communities safe and organized.', 'discussion', '["traffic light picture","colored paper"]'::jsonb, '["hfle","social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('3e6f78f5-b973-4444-b3c2-294a08cf92af', 'science', '1', 'Waves, Light and Sound', '4', 10, 'Morse Code Introduction', 'Listen to Morse code samples and learn that a system of beeps and pauses was developed like an alphabet to make whole words.', 'discussion', '["Morse code chart","audio recording"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('83978861-efff-4f09-bc97-1c8ee71952db', 'science', '1', 'Waves, Light and Sound', '4', 11, 'Class Debate', 'Discuss: How do light and sound warnings assist the blind and deaf in our community? How can we improve these systems?', 'discussion', NULL, '["hfle","social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:24:27.697515+00:00', '2026-01-09T12:24:27.697515+00:00'),
  ('3dd48c5b-f881-4900-8a41-52db18dcf7d3', 'science', '1', 'Structure, Function and Information Processing', '1', 1, 'Mimicking Design Challenge', 'Students design and build a tool to reach something high (mimicking a giraffe''s neck) using broomstick, tape, screws, and plastic cup/bottle.', 'hands-on', '["broomstick","tape","screws","plastic cup","plastic bottle"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('8138e613-f2b5-47b1-8cb3-4f4f9c8309a1', 'science', '1', 'Structure, Function and Information Processing', '1', 2, 'Matching Activity', 'Match pictures of animals/plants to the technology which mimics them using cutouts.', 'game', '["picture cutouts of animals","picture cutouts of technology"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('ae73c140-d4d7-40b7-91b8-af9529f3c1c2', 'science', '1', 'Structure, Function and Information Processing', '1', 3, 'Nature Walk - Shameplant Observation', 'Observe the Mimosa pudica (shameplant) in nature and touch it to see the response.', 'movement', '["clipboard","paper","pencil"]'::jsonb, '["agriculture"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('1e67bc7d-6b0c-4fdd-a6ab-55e58df19ce1', 'science', '1', 'Structure, Function and Information Processing', '1', 4, 'Shameplant Drawing', 'Record observations by drawing the plant''s leaves before and after being touched.', 'art', '["paper","crayons","colored pencils"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('43851a9f-4208-4f1d-8812-13d26dcf8368', 'science', '1', 'Structure, Function and Information Processing', '1', 5, 'Shameplant Roleplay', 'Students mimic the movement of the shameplant through the open/close motion of their hands in pairs.', 'movement', NULL, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('0d8c2bb7-261e-453f-8e92-d5958383bee9', 'science', '1', 'Structure, Function and Information Processing', '1', 6, 'Flamingo Discussion', 'Discuss how humans mimic the flamingo (stilts for plastering ceilings).', 'discussion', '["flamingo pictures","stilt pictures"]'::jsonb, '["tvet","social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('7afcb7b1-7eed-4337-ad5b-1e5cfad1d58d', 'science', '1', 'Structure, Function and Information Processing', '1', 7, 'Defence and Camouflage Discussion', 'Discuss how animals mimic each other for defence and how humans use camouflage (soldiers, hunters).', 'discussion', '["camouflage pictures","animal pictures"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('44573913-6e34-461b-8f80-40b52299fd63', 'science', '1', 'Structure, Function and Information Processing', '1', 8, 'Lionfish/Barbed Wire Comparison', 'Compare pictures of lionfish spines to see how humans invented barbed wire.', 'discussion', '["lionfish pictures","barbed wire pictures"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('ae59d73e-b073-4e55-b1b9-ed80b5c5b12d', 'science', '1', 'Structure, Function and Information Processing', '1', 9, 'Lizard/Suction Cup Comparison', 'Observe how humans mimicked the gecko''s feet to create suction cups.', 'discussion', '["gecko pictures","suction cups"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('b92fefdf-c9b3-41f1-b325-b398db994bfe', 'science', '1', 'Structure, Function and Information Processing', '2', 1, 'Which is the Parent?', 'Matching card game pairing animal parents with their offspring.', 'game', '["matching cards with parent animals","matching cards with offspring"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('e986a1cb-224d-4fcb-8c51-18192f128f71', 'science', '1', 'Structure, Function and Information Processing', '2', 2, 'Categorizing Behaviours', 'Small groups sort photos into categories: Feeding, Carrying, and Protecting.', 'hands-on', '["photos of animals caring for babies","sorting mats","category labels"]'::jsonb, NULL, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('cc2a2404-c183-4792-a4ed-bf316cd3a792', 'science', '1', 'Structure, Function and Information Processing', '2', 3, 'Whole Class Discussion', 'Discuss how parents support children using a baby doll or picture of a newborn.', 'discussion', '["baby doll","picture of newborn baby"]'::jsonb, '["hfle","social-studies"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('97579d7b-c8ba-4e02-80b9-e582eda14a37', 'science', '1', 'Structure, Function and Information Processing', '2', 4, 'Human Signals Discussion', 'Students discuss how they signal hunger, hurt, sickness, loneliness, and happiness to parents, and how parents respond.', 'discussion', '["emotion picture cards"]'::jsonb, '["hfle","language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('3674b965-5c61-461f-a5bb-2f8d789fd480', 'science', '1', 'Structure, Function and Information Processing', '2', 5, 'Field Trip', 'Visit a farm, zoo, or take a nature walk to observe parent/offspring behaviours in real animals.', 'movement', '["clipboard","paper","pencil","camera"]'::jsonb, '["social-studies","agriculture"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('cd29e930-7116-44e6-902d-66c2cc6ce215', 'science', '1', 'Structure, Function and Information Processing', '2', 6, 'In-Class Video Observation', 'Groups view pictures or videos of parents and offspring in different survival situations.', 'video', '["projector","screen","internet access"]'::jsonb, NULL, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('9dc1bf46-0177-4fe8-9b3c-8956c0b30fd1', 'science', '1', 'Structure, Function and Information Processing', '2', 7, 'Scenario Roleplay', 'Role play scenarios: baby bird chirping hungrily to be fed; baby wanting to sleep and parent comforting.', 'movement', '["simple props for roleplay"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('de268fd6-a0c7-4c04-94eb-9945810ac798', 'science', '1', 'Structure, Function and Information Processing', '2', 8, 'Literacy Connections', 'Complete words/verbs for common animal behaviours (E_t, C_y, R_n, etc.).', 'worksheet', '["worksheets","pencils"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('02b76e88-1c74-4184-814b-469d5cd864b6', 'science', '1', 'Structure, Function and Information Processing', '2', 9, 'Mama Hen Story Time', 'Listen to the story of Mama Hen and the mongoose, then answer response questions about signals and protection.', 'discussion', '["storybook or story script"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('43b6d93f-3d1a-47dc-a10f-84202a4f7861', 'science', '1', 'Structure, Function and Information Processing', '2', 10, 'Sound Identification Game', 'Listen to animal sounds and identify which baby animal is making the sound.', 'game', '["audio player","animal sound recordings","picture cards"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('2743e965-25d8-4c9f-aae5-7b07067eda3e', 'science', '1', 'Structure, Function and Information Processing', '2', 11, 'Finding Sounds Outside', 'With parent help, students record animal/offspring sounds at home to share with the class.', 'hands-on', '["recording device","parent permission slip"]'::jsonb, '["social-studies"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('ecbd4953-2aa7-480f-a2e3-88c9b2b8eef1', 'science', '1', 'Structure, Function and Information Processing', '2', 12, 'Creating Shelter', 'Watch video about animal shelters and build a simple shelter for a caterpillar using coffee sticks, toothpicks, paper, and glue.', 'hands-on', '["coffee sticks","toothpicks","paper","glue","scissors"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('205e1f62-78c7-4831-af4c-61374eae9f97', 'science', '1', 'Structure, Function and Information Processing', '3', 1, 'My Favourite Animal Drawing', 'Draw your favourite animal as both a parent and a baby, then present to the class explaining similarities and differences.', 'art', '["paper","crayons","colored pencils"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('0c410e2e-fe03-484f-a5b0-acb3b6857d44', 'science', '1', 'Structure, Function and Information Processing', '3', 2, 'Playdough Modelling', 'Create models of favourite plant/animal as both parent and baby using playdough.', 'hands-on', '["playdough","modelling tools"]'::jsonb, '["tvet"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('288ee05c-01b1-4c0a-b0b4-6b4dc82e7ca6', 'science', '1', 'Structure, Function and Information Processing', '3', 3, 'KWL Chart', 'Track what students Know, Want to know, and have Learned about young animals and their parents.', 'worksheet', '["KWL chart templates","pencils"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('a677e455-4bde-4dd5-8fb6-6972369a66f4', 'science', '1', 'Structure, Function and Information Processing', '3', 4, 'Comparing Young and Adult Plants', 'Visit a farm or view specimens to compare mango, tomato, and hibiscus plants using a T-chart.', 'hands-on', '["T-chart templates","plant specimens or pictures","pencils"]'::jsonb, '["agriculture","mathematics"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('c81ea0d5-ae91-40ea-9d36-c3add4a5b02d', 'science', '1', 'Structure, Function and Information Processing', '3', 5, 'Comparing Young and Adult Animals', 'Observe cat/kitten, goat/kid, bird/chick pairs and compare using a T-chart.', 'hands-on', '["T-chart templates","animal pictures","pencils"]'::jsonb, '["mathematics"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('268f947c-a338-4dc5-a37c-c1a081222623', 'science', '1', 'Structure, Function and Information Processing', '3', 6, 'Matching Exercise', 'Match parts of young animals/plants to their corresponding adult parts.', 'game', '["matching cards","picture cutouts"]'::jsonb, NULL, NULL, NULL, 'pairs', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('0a3e88eb-c887-4385-87b5-98e5a6b0f980', 'science', '1', 'Structure, Function and Information Processing', '3', 7, 'Drawing a Matching Offspring', 'Look at a picture of an adult animal and draw what you think the baby would look like.', 'art', '["adult animal pictures","paper","crayons"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('797c94bb-1763-4ca2-922d-bbd672a4aa5d', 'science', '1', 'Structure, Function and Information Processing', '3', 8, 'Video Comparison Activity', 'Watch "Baby Animals That Grow Up to Look Totally Different" twice - first for similarities, second for differences.', 'video', '["projector","screen","internet access","comparison worksheet"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('cee603db-bcaf-4b47-9841-1554fb1f0f77', 'science', '1', 'Structure, Function and Information Processing', '3', 9, 'Who Do I Most Look Like?', 'Students bring photos of themselves and their parents to compare characteristics and discuss which parent they resemble most.', 'discussion', '["family photos from home"]'::jsonb, '["social-studies","hfle"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:33:35.273801+00:00', '2026-01-09T12:33:35.273801+00:00'),
  ('4c78f4b4-224e-431e-957f-59f4702304e4', 'language-arts', '1', 'Listening and Speaking', '1', 1, 'Music Moments', 'Schedule opportunities throughout the day to pause, relax and listen for pleasure with brief selections of music.', 'listening', '["audio player","speaker","music selections"]'::jsonb, '["music"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('d4c9af60-be6e-4906-bec9-94f5410a8cb1', 'language-arts', '1', 'Listening and Speaking', '1', 2, 'The Sounds of Silence', 'Gather learners to create total silence and listen to ambient sounds; discuss the messages each sound conveys.', 'discussion', NULL, '["hfle"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('91933a7e-68d7-449a-a6fb-dc1bf2c55d9e', 'language-arts', '1', 'Listening and Speaking', '1', 3, 'Sound Walk', 'Take learners on a walk around the school to identify and categorize different sounds they hear.', 'movement', '["clipboard","paper","pencil"]'::jsonb, '["science"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('630bd9cc-7879-429c-8044-8b179b019ebb', 'language-arts', '1', 'Listening and Speaking', '1', 4, 'Daily Read Alouds', 'Schedule daily Teacher Read Alouds with a variety of texts relevant to learner interests.', 'reading', '["picture books","story books"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('c770e454-d579-4924-9850-7007e0f7d0d7', 'language-arts', '1', 'Listening and Speaking', '1', 5, 'Story Response', 'After listening to stories, learners draw or verbally share their favourite parts.', 'art', '["paper","crayons","colored pencils"]'::jsonb, NULL, NULL, NULL, 'individual', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('394c347c-736f-4ef4-ade9-2f4e7efc686f', 'language-arts', '1', 'Listening and Speaking', '1', 6, 'Prediction Station', 'Pause during read alouds to ask learners what they think will happen next.', 'discussion', '["story books"]'::jsonb, NULL, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
  ('87b3f49d-df89-4cd8-915f-8444a44e1a5b', 'language-arts', '1', 'Listening and Speaking', '1', 7, 'Sound Detectives', 'Play recordings of environmental sounds and have learners identify the source.', 'game', '["audio player","environmental sound recordings","picture cards"]'::jsonb, '["science"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T12:43:56.398298+00:00', '2026-01-09T12:43:56.398298+00:00'),
