  ('9fd58434-ba69-421f-8fcd-7912da9c4dc4', 'social-studies', '1', 'Historical and Cultural Thinking', '1', 1, 'Family Celebrations Brainstorm', 'Students brainstorm different forms of celebrations practiced in families such as birthdays, weddings, christenings/baptisms, wakes, Christmas, and Easter. Create a class chart categorizing celebrations.', 'discussion', '["chart paper","markers","celebration pictures"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:08.692102+00:00', '2026-01-09T15:05:08.692102+00:00'),
  ('d6e75161-470d-4c35-8d29-58a6c8dabbd3', 'social-studies', '1', 'Historical and Cultural Thinking', '1', 2, 'Cultural Elements Matching', 'Students identify aspects of culture such as food, music, and dance that are relevant to celebrations in families. Match cultural elements to specific celebrations using picture cards.', 'matching', '["picture cards","matching worksheet","cultural images"]'::jsonb, '["language-arts","music"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:05:08.692102+00:00', '2026-01-09T15:05:08.692102+00:00'),
  ('84f2b3de-58c8-438d-992c-2d0c0b2d1669', 'social-studies', '1', 'Historical and Cultural Thinking', '1', 3, 'Religious and National Festivals Calendar', 'Students list religious festivals like Christmas and Easter, and national festivals like Independence Day and Carnival. Create a class calendar showing when these festivals occur.', 'investigation', '["calendar template","festival pictures","markers","stickers"]'::jsonb, '["mathematics","language-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:08.692102+00:00', '2026-01-09T15:05:08.692102+00:00'),
