  ('52b7b37c-5202-4d67-9669-7149635fd69b', 'social-studies', '1', 'Historical and Cultural Thinking', '1', 5, 'Celebration Role Play', 'Students role-play aspects of family celebrations including traditional foods, dance, and music. Demonstrate different forms of celebration and explain the importance of preserving local culture.', 'role-play', '["costumes","props","musical instruments","traditional items"]'::jsonb, '["drama","music","physical-education"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:08.692102+00:00', '2026-01-09T15:05:08.692102+00:00'),
