  ('2891f1e3-f7fc-43ae-8f32-1bf83e7d016a', 'social-studies', '1', 'Civic Participation', '1', 7, 'Family Helpers List', 'Students list the ways that siblings, parents, grandparents, and other relatives help them and vice versa. Create a two-column chart showing giving and receiving help.', 'investigation', '["chart paper","markers","family worksheet"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('fc813984-75bd-4751-96ac-9ac35286160c', 'social-studies', '1', 'Civic Participation', '1', 8, 'Safety Communication Practice', 'Students communicate ways to express when they feel unsafe. Practice effective communication strategies to express feelings of discomfort or danger.', 'role-play', '["scenario cards","feeling faces","safety worksheet"]'::jsonb, '["health","language-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('7464c574-299c-4857-ad86-e6872d655d68', 'social-studies', '1', 'Civic Participation', '1', 9, 'Leaders in My World', 'Students identify leaders in their home, school, church, community, and nation. Play matching games connecting leaders with their roles.', 'matching', '["leader picture cards","role cards","matching worksheet"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('8aea08e8-5ced-4db4-9678-bdcd74b4447d', 'social-studies', '1', 'Civic Participation', '1', 10, 'Manners Role Play', 'Students practice using proper manners when interacting with adults. Role-play scenarios demonstrating saying "please," "thank you," and showing respect.', 'role-play', '["scenario cards","manners poster","reward stickers"]'::jsonb, '["language-arts","drama"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('37e419f5-198c-4897-9e8d-7218466bbb5c', 'social-studies', '1', 'Civic Participation', '1', 11, 'Clean Spaces Appreciation Walk', 'Students observe and appreciate places in their environment that are kept clean and tidy. Take a walk around school to identify and appreciate clean spaces.', 'gallery-walk', '["observation checklist","clipboards","pencils"]'::jsonb, '["health","science"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('5162f148-017e-43aa-baae-6f7630806b4d', 'social-studies', '1', 'Civic Participation', '1', 12, 'Helping Hands Collage', 'Students appreciate that helping other family members is important for collective wellbeing. Create collages showing family members helping each other.', 'creative', '["magazines","scissors","glue","poster paper"]'::jsonb, '["visual-arts","language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('40b0f2fd-50d3-40d1-a4ef-8fdaece36065', 'social-studies', '1', 'Civic Participation', '1', 13, 'Safe Feelings Journal', 'Students appreciate feeling safe in their environment. Journal about times they felt safe and strategies to maintain personal safety.', 'reflection', '["journals","pencils","feeling faces chart"]'::jsonb, '["language-arts","health"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('f38e18d4-d8f8-4acc-95bc-e8bbc2081cd1', 'social-studies', '1', 'Civic Participation', '1', 14, 'Leaders Help Us', 'Students appreciate that leaders are an important part of our well-being. Discuss how leaders solve problems and support community well-being.', 'discussion', '["leader pictures","chart paper","markers"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('3cc6a3a3-8406-4053-81bf-c2b97708a5ad', 'social-studies', '1', 'Civic Participation', '1', 15, 'Respect in Action', 'Students demonstrate respect for persons in authority through appropriate behaviors and manners. Create a manners mobile with words showing respect.', 'creative', '["cardstock","string","markers","hole punch","hangers"]'::jsonb, '["visual-arts","language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:33.5364+00:00', '2026-01-09T15:05:33.5364+00:00'),
  ('477c3cc5-6dd9-4930-9a5a-1f8e64247931', 'social-studies', '1', 'Spatial Thinking', '1', 1, 'My Home Address', 'Students identify where their family lives. Practice stating their address and describing their home and immediate surroundings.', 'discussion', '["address cards","home pictures","neighborhood map"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('06ce942e-341a-4b28-8504-6e2b8919da96', 'social-studies', '1', 'Spatial Thinking', '1', 2, 'Relative Location Vocabulary', 'Students understand basic terms for relative location: near and far, next to, opposite, in front, and behind. Practice using these terms to describe locations.', 'demonstration', '["classroom objects","location word cards","pictures"]'::jsonb, '["language-arts","mathematics"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('4627f208-407e-4fcf-aef3-c1cd444cf145', 'social-studies', '1', 'Spatial Thinking', '1', 3, 'Cardinal Directions Introduction', 'Students name and illustrate the four cardinal directions (North, South, East, West). Create compass roses and understand their use in navigation.', 'creative', '["compass rose template","markers","construction paper"]'::jsonb, '["mathematics","visual-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('9b5a2986-24f3-4bf6-960f-f70f2d067683', 'social-studies', '1', 'Spatial Thinking', '1', 4, 'Family Activities Because of Location', 'Students list activities that they and their family engage in because of where they live. Discuss how location influences available activities.', 'discussion', '["activity pictures","chart paper","markers"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('763afd62-f65e-4dc8-b2fa-9dd35a139f0c', 'social-studies', '1', 'Spatial Thinking', '1', 5, 'Natural Hazards Identification', 'Students identify natural hazards which may pose a threat to their family because of where they live, such as hurricanes, tsunamis, volcanic eruptions, and earthquakes.', 'discussion', '["hazard pictures","local map","chart paper"]'::jsonb, '["science","health"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00');
INSERT INTO curriculum_activities (id, subject, grade_level, strand, elo_number, activity_number, title, description, activity_type, materials, integration_subjects, difficulty_level, duration_minutes, group_size, sort_order, created_at, updated_at) VALUES
  ('0392c5fe-9be3-45d9-8fd2-dcbee67bbc5b', 'social-studies', '1', 'Spatial Thinking', '1', 6, 'Home and Neighbors Drawing', 'Students locate their home in relation to their closest neighbours. Draw pictures of their home and neighbors'' homes, identifying relative positions.', 'creative', '["drawing paper","crayons","markers"]'::jsonb, '["visual-arts","mathematics"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('ae10a904-20d6-4188-9e68-87f916159ad0', 'social-studies', '1', 'Spatial Thinking', '1', 7, 'Near and Far Mapping', 'Students distinguish between and show near and far in their immediate environment. Create simple maps showing objects, people, and places that are near or far.', 'creative', '["paper","markers","rulers","mapping symbols"]'::jsonb, '["mathematics","visual-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('d616851b-3c47-4e30-a5db-5eeabee27f35', 'social-studies', '1', 'Spatial Thinking', '1', 8, 'Neighborhood Description Practice', 'Students use relative location to describe places in their neighbourhood. Practice giving directions using terms like next to, opposite, in front, and behind.', 'role-play', '["neighborhood pictures","direction cards","simple maps"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('efe429fc-3031-4b51-b0ae-9aa31116f88e', 'social-studies', '1', 'Spatial Thinking', '1', 9, 'Cardinal Directions Home Location', 'Students describe the location of their home using cardinal directions in relation to natural and built features.', 'investigation', '["compass","local area map","direction worksheet"]'::jsonb, '["mathematics","language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('5a3e2003-1233-4c05-8bc7-bb12afe6354c', 'social-studies', '1', 'Spatial Thinking', '1', 10, 'Family Activities Impact Chart', 'Students classify family activities as having a positive or negative impact on the neighbourhood. Create cause-and-effect charts.', 'sorting', '["activity cards","sorting mat","chart paper","markers"]'::jsonb, '["language-arts","science"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('39f00d69-c14e-457c-b434-df24eac171d8', 'social-studies', '1', 'Spatial Thinking', '1', 11, 'Evacuation Drill Practice', 'Students demonstrate how to follow evacuation procedures in their school. Create maps showing evacuation routes.', 'demonstration', '["school map","evacuation route signs","markers"]'::jsonb, '["health","physical-education"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('d977079c-0d18-4adf-8692-5e1f416a211a', 'social-studies', '1', 'Spatial Thinking', '1', 12, 'Neighborhood Appreciation Walk', 'Students appreciate that their family lives in a neighbourhood. Take a nature walk to observe and recognize the importance of their neighborhood and the people who live there.', 'gallery-walk', '["clipboards","observation sheets","pencils"]'::jsonb, '["science","health"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('dcf057e8-353f-469f-a1ce-164166947abd', 'social-studies', '1', 'Spatial Thinking', '1', 13, 'Location Words Importance Journal', 'Students recognize the importance of being able to describe relative location. Journal about times when location words helped find things or navigate.', 'reflection', '["journals","pencils","location word list"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('315bb010-0bf1-48bf-8bdc-39c2bd406269', 'social-studies', '1', 'Spatial Thinking', '1', 14, 'Activities and Location Connection', 'Students appreciate that relative location can influence activities that families engage in. Discuss how living near beaches, mountains, or cities affects daily life.', 'discussion', '["location pictures","activity cards","chart paper"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('dbecb8ab-4045-49a1-a745-49c8340b156b', 'social-studies', '1', 'Spatial Thinking', '1', 15, 'Cardinal Directions Navigation Game', 'Students appreciate the value of directions for finding their way. Play the game "North-South-East-West! Choose the one you love the best" to practice navigation.', 'game', '["direction signs","open space","music"]'::jsonb, '["physical-education","mathematics"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('7027a631-1bca-4f2a-8fe0-c0607e5e9dd0', 'social-studies', '1', 'Spatial Thinking', '1', 16, 'People and Environment Relationship', 'Students recognize that where we live influences how our families live and that our actions impact our neighbourhood. Create posters showing this relationship.', 'creative', '["poster paper","magazines","scissors","glue","markers"]'::jsonb, '["visual-arts","science"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('338d50f6-955d-45ac-9d16-5d24ce53cdc3', 'social-studies', '1', 'Spatial Thinking', '1', 17, 'Natural Disaster Safety Poster', 'Students respect the dangers posed by natural disasters. Create safety posters showing appropriate responses to various natural hazards.', 'creative', '["poster paper","markers","safety information sheets"]'::jsonb, '["visual-arts","health"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:05:51.441055+00:00', '2026-01-09T15:05:51.441055+00:00'),
  ('7ee3cf17-9ef8-48b3-909d-8e56a0621a62', 'social-studies', '1', 'Economic Decision Making', '1', 1, 'Basic Human Needs Identification', 'Students identify basic human needs such as food, water, shelter, and clothing that are necessary for survival. Create a class chart of essential needs.', 'discussion', '["needs pictures","chart paper","markers"]'::jsonb, '["language-arts","health"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('a7e138b6-36e6-4f32-8dd9-fa8e8b6e5b44', 'social-studies', '1', 'Economic Decision Making', '1', 2, 'Goods and Services Understanding', 'Students understand that we meet most of our needs and wants through goods and services. Learn that goods are tangible items we can buy and hold, while services are actions people do to help others.', 'discussion', '["goods pictures","services pictures","chart paper"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('88f2114d-83a2-4e0b-afc6-95bff255296b', 'social-studies', '1', 'Economic Decision Making', '1', 3, 'Environmental Resources Exploration', 'Students identify things in the environment that we use. Recognize natural and man-made resources and understand how these are used.', 'investigation', '["resource pictures","nature items","chart paper"]'::jsonb, '["science","language-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('f5623b20-96c1-46f5-887d-9aee0b7ff647', 'social-studies', '1', 'Economic Decision Making', '1', 4, 'Transportation Forms', 'Students understand the various forms of transportation in their local environment. Identify different modes for moving people and goods from one place to another.', 'discussion', '["transportation pictures","toy vehicles","chart paper"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('590f1a26-5c9a-433c-a93d-ce27ae08496b', 'social-studies', '1', 'Economic Decision Making', '1', 5, 'Needs vs Wants Sorting', 'Students distinguish between basic needs and wants. Categorize items as needs (essential for survival) or wants (desired but not necessary for survival).', 'sorting', '["picture cards","sorting mats labeled \"Needs\" and \"Wants\"","worksheet"]'::jsonb, '["mathematics","language-arts"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('272b4d28-04d2-4a2f-9b6a-b930fee5bfe9', 'social-studies', '1', 'Economic Decision Making', '1', 6, 'Goods or Services Classification', 'Students categorise needs and wants as goods or services. Sort various items and activities into goods (tangible) or services (intangible).', 'sorting', '["goods/services cards","sorting chart","markers"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('5c432635-f7e5-47f9-8df2-d3aea2d6b48b', 'social-studies', '1', 'Economic Decision Making', '1', 7, 'Using Environmental Resources', 'Students discuss how we use things in the environment. Explain how natural resources like water, wood, and soil are used to meet human needs and wants.', 'discussion', '["resource samples","product pictures","matching cards"]'::jsonb, '["science","language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('2f4f9512-3563-47ff-89b1-ffe388ef8f78', 'social-studies', '1', 'Economic Decision Making', '1', 8, 'Transportation Comparison', 'Students distinguish different forms of transportation and their benefits and limitations. Compare various modes (land, water, air) and identify their appropriate uses.', 'sorting', '["transportation pictures","comparison chart","markers"]'::jsonb, '["language-arts","science"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('93f6b6b1-913d-499f-ab86-6da4e5b9017c', 'social-studies', '1', 'Economic Decision Making', '1', 9, 'Appreciating Needs vs Wants', 'Students appreciate the difference between needs and wants. Understand the importance of prioritizing needs over wants and that not all desires are necessities.', 'reflection', '["journals","pencils","scenario cards"]'::jsonb, '["language-arts","health"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('ea94f2dd-cac9-4c2e-99d7-b68a01f5f304', 'social-studies', '1', 'Economic Decision Making', '1', 10, 'Goods and Services Value', 'Students appreciate that goods and services are necessary to meet our needs and wants. Recognize the value of both in satisfying human needs.', 'discussion', '["picture cards","chart paper","markers"]'::jsonb, '["language-arts"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('d0a5a5e9-2664-477d-bd17-8933fba2aabe', 'social-studies', '1', 'Economic Decision Making', '1', 11, 'Environmental Stewardship', 'Students appreciate that the environment can be used to provide our needs and wants. Develop understanding of how environmental resources contribute to well-being and the importance of using resources responsibly.', 'creative', '["poster paper","crayons","nature pictures","magazines"]'::jsonb, '["science","visual-arts"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('6f4c8a8c-27c4-4710-b328-33c33c9e0055', 'social-studies', '1', 'Economic Decision Making', '1', 12, 'Transportation Safety Appreciation', 'Students appreciate the importance of exercising safety around transportation. Value safety practices when using or being around various forms of transportation.', 'demonstration', '["safety signs","role-play props","safety rules poster"]'::jsonb, '["health","physical-education"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('d98be766-5c7a-4545-a735-c6a6079cde66', 'social-studies', '1', 'Economic Decision Making', '1', 13, 'Class Shop Role Play', 'Students role-play running a class shop to understand buying and selling goods. Practice exchanging goods for pretend money.', 'role-play', '["play money","shop items","price tags","shopping bags"]'::jsonb, '["mathematics","drama"]'::jsonb, NULL, NULL, 'small-group', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('b8901894-5214-4203-b476-c02208882ea3', 'social-studies', '1', 'Economic Decision Making', '1', 14, 'Taking Care of Dolls/Teddy Bears', 'Students demonstrate meeting basic needs through caring for dolls or teddy bears. Practice providing food, clothing, and shelter for their "dependents".', 'role-play', '["dolls/teddy bears","doll clothes","toy food","blankets"]'::jsonb, '["health","drama"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('d10a5e93-2c9c-480b-ad5c-fb0fe74204e1', 'social-studies', '1', 'Economic Decision Making', '1', 15, 'Goods and Services Poster', 'Students create posters showing examples of goods and services in their community. Draw or cut out pictures to categorize.', 'creative', '["poster paper","magazines","scissors","glue","markers"]'::jsonb, '["visual-arts","language-arts"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('88d98c57-2687-40ed-8915-e67341188181', 'social-studies', '1', 'Economic Decision Making', '1', 16, 'Natural Resources Matching Game', 'Students match everyday items with the natural resources they come from. Connect products to their origins (e.g., paper from trees, bread from wheat).', 'matching', '["resource cards","product cards","matching worksheet"]'::jsonb, '["science"]'::jsonb, NULL, NULL, 'pairs', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('f8e4095f-0886-4fd9-8bb0-8b3d5370d883', 'social-studies', '1', 'Economic Decision Making', '1', 17, 'Wise Resource Use', 'Students demonstrate conservation activities showing wise use of resources. Practice turning off lights, saving water, and reducing waste.', 'demonstration', '["conservation checklist","reminder signs","recycling bins"]'::jsonb, '["science","health"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('53b8069f-c806-46a6-a36b-de4e698e2053', 'social-studies', '1', 'Economic Decision Making', '1', 18, 'Transportation Mobile', 'Students create art projects showing different forms of transportation. Make mobiles with land, water, and air vehicles.', 'creative', '["cardstock","string","hangers","markers","scissors"]'::jsonb, '["visual-arts"]'::jsonb, NULL, NULL, 'individual', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00'),
  ('7eb2cdbe-936a-4793-b2ea-1d81ffc84a19', 'social-studies', '1', 'Economic Decision Making', '1', 19, 'Transportation Field Trip', 'Students observe different forms of transportation during a field trip or neighborhood walk. Document various vehicles and their purposes.', 'investigation', '["clipboards","observation sheets","cameras (optional)"]'::jsonb, '["language-arts","science"]'::jsonb, NULL, NULL, 'whole-class', 0, '2026-01-09T15:06:05.920061+00:00', '2026-01-09T15:06:05.920061+00:00');
